import React, { useState } from 'react';
import { Send, MessageSquare } from 'lucide-react';

const THREADS = [
  { id: 1, name: 'Design Team', avatar: 'D', color: '#d946ef', lastMsg: 'Artwork uploaded for order #ORD-042', time: '11:24 AM', unread: 2 },
  { id: 2, name: 'Accounts', avatar: 'A', color: '#10b981', lastMsg: 'Invoice #INV-019 payment received', time: '10:58 AM', unread: 0 },
  { id: 3, name: 'Order Management', avatar: 'O', color: '#f97316', lastMsg: 'ORD-037 approved to production', time: '10:15 AM', unread: 1 },
  { id: 4, name: 'Production Floor', avatar: 'P', color: '#3b82f6', lastMsg: 'Batch #PROD-11 complete, ready dispatch', time: 'Yesterday', unread: 0 },
  { id: 5, name: 'Delivery Team', avatar: 'DT', color: '#f43f5e', lastMsg: 'ORD-031 delivered successfully', time: 'Yesterday', unread: 0 },
];

const MESSAGES = {
  1: [
    { from: 'Design Team', text: 'Hey, artwork for ORD-042 is uploaded. Please review and approve.', time: '11:20 AM', own: false },
    { from: 'Me', text: 'Got it, reviewing now!', time: '11:22 AM', own: true },
    { from: 'Design Team', text: 'Artwork uploaded for order #ORD-042', time: '11:24 AM', own: false },
  ],
  2: [
    { from: 'Accounts', text: 'Invoice #INV-019 has been paid by the client.', time: '10:55 AM', own: false },
    { from: 'Me', text: 'Thanks, confirming receipt now.', time: '10:57 AM', own: true },
    { from: 'Accounts', text: 'Invoice #INV-019 payment received', time: '10:58 AM', own: false },
  ],
  3: [
    { from: 'Order Management', text: 'We have reviewed ORD-037 and approved it.', time: '10:12 AM', own: false },
    { from: 'Order Management', text: 'ORD-037 approved to production', time: '10:15 AM', own: false },
  ],
  4: [
    { from: 'Production Floor', text: 'Batch #PROD-11 embroidery & print complete. Package sealed.', time: 'Yesterday', own: false },
  ],
  5: [
    { from: 'Delivery Team', text: 'ORD-031 delivered to client. Balance collected.', time: 'Yesterday', own: false },
  ],
};

const MockInbox = () => {
  const [selectedThread, setSelectedThread] = useState(1);
  const [draft, setDraft] = useState('');
  const [threads, setThreads] = useState(THREADS);
  const [messages, setMessages] = useState(MESSAGES);

  const handleSend = () => {
    if (!draft.trim()) return;
    const now = new Date();
    const timeStr = now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });
    const newMsg = { from: 'Me', text: draft, time: timeStr, own: true };
    setMessages(prev => ({ ...prev, [selectedThread]: [...(prev[selectedThread] || []), newMsg] }));
    setThreads(prev => prev.map(t => t.id === selectedThread ? { ...t, lastMsg: draft, time: timeStr, unread: 0 } : t));
    setDraft('');
  };

  const selectThread = (id) => {
    setSelectedThread(id);
    setThreads(prev => prev.map(t => t.id === id ? { ...t, unread: 0 } : t));
  };

  const currentThread = threads.find(t => t.id === selectedThread);
  const currentMessages = messages[selectedThread] || [];

  return (
    <div style={{ display: 'flex', gap: '0', height: '520px', border: '1px solid var(--border-color)', borderRadius: '16px', overflow: 'hidden' }}>

      {/* Thread List Sidebar */}
      <div style={{ width: '280px', borderRight: '1px solid var(--border-color)', background: 'rgba(0,0,0,0.1)', display: 'flex', flexDirection: 'column', flexShrink: 0 }}>
        <div style={{ padding: '18px 20px', borderBottom: '1px solid var(--border-color)' }}>
          <h3 style={{ fontSize: '1rem', fontWeight: 800, color: 'var(--text-primary)', margin: 0, display: 'flex', alignItems: 'center', gap: '8px' }}>
            <MessageSquare size={18} /> Inbox
          </h3>
          <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Internal Pallywear Messaging</span>
        </div>
        <div style={{ flex: 1, overflowY: 'auto' }}>
          {threads.map(t => (
            <div
              key={t.id}
              onClick={() => selectThread(t.id)}
              style={{
                padding: '14px 20px',
                display: 'flex',
                alignItems: 'center',
                gap: '12px',
                cursor: 'pointer',
                background: selectedThread === t.id ? 'rgba(255,255,255,0.04)' : 'transparent',
                borderLeft: selectedThread === t.id ? `3px solid ${t.color}` : '3px solid transparent',
                transition: 'all 0.15s'
              }}
            >
              <div style={{ width: '38px', height: '38px', borderRadius: '50%', background: t.color, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontWeight: 800, fontSize: '0.78rem', flexShrink: 0 }}>
                {t.avatar}
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <span style={{ fontWeight: 700, fontSize: '0.88rem', color: 'var(--text-primary)' }}>{t.name}</span>
                  {t.unread > 0 && (
                    <span style={{ background: t.color, color: '#fff', fontSize: '0.65rem', fontWeight: 800, borderRadius: '10px', padding: '1px 6px' }}>{t.unread}</span>
                  )}
                </div>
                <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', overflow: 'hidden', whiteSpace: 'nowrap', textOverflow: 'ellipsis', marginTop: '2px' }}>
                  {t.lastMsg}
                </div>
                <div style={{ fontSize: '0.68rem', color: 'var(--text-muted)', marginTop: '2px' }}>{t.time}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Chat Panel */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', background: 'rgba(0,0,0,0.04)' }}>
        {/* Header */}
        <div style={{ padding: '16px 24px', borderBottom: '1px solid var(--border-color)', background: 'rgba(0,0,0,0.05)', display: 'flex', alignItems: 'center', gap: '12px' }}>
          <div style={{ width: '36px', height: '36px', borderRadius: '50%', background: currentThread?.color, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#fff', fontWeight: 800, fontSize: '0.75rem' }}>
            {currentThread?.avatar}
          </div>
          <div>
            <div style={{ fontWeight: 700, fontSize: '0.95rem', color: 'var(--text-primary)' }}>{currentThread?.name}</div>
            <div style={{ fontSize: '0.72rem', color: '#10b981' }}>● Online</div>
          </div>
        </div>

        {/* Messages */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '20px 24px', display: 'flex', flexDirection: 'column', gap: '12px' }}>
          {currentMessages.map((msg, i) => (
            <div key={i} style={{ display: 'flex', justifyContent: msg.own ? 'flex-end' : 'flex-start' }}>
              <div style={{
                maxWidth: '72%',
                padding: '10px 14px',
                borderRadius: msg.own ? '16px 16px 4px 16px' : '16px 16px 16px 4px',
                background: msg.own ? 'var(--color-marketing, #bf00af)' : 'rgba(255,255,255,0.06)',
                border: msg.own ? 'none' : '1px solid var(--border-color)',
                color: msg.own ? '#fff' : 'var(--text-primary)',
                fontSize: '0.88rem'
              }}>
                {!msg.own && <div style={{ fontSize: '0.7rem', fontWeight: 700, marginBottom: '4px', opacity: 0.7 }}>{msg.from}</div>}
                {msg.text}
                <div style={{ fontSize: '0.65rem', marginTop: '4px', opacity: 0.6, textAlign: msg.own ? 'right' : 'left' }}>{msg.time}</div>
              </div>
            </div>
          ))}
        </div>

        {/* Input */}
        <div style={{ padding: '14px 20px', borderTop: '1px solid var(--border-color)', display: 'flex', gap: '10px', background: 'rgba(0,0,0,0.05)' }}>
          <input
            type="text"
            placeholder="Type a message..."
            value={draft}
            onChange={e => setDraft(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleSend()}
            style={{ flex: 1, padding: '10px 14px', borderRadius: '10px', border: '1px solid var(--border-color)', background: 'rgba(0,0,0,0.2)', color: 'var(--text-primary)', fontSize: '0.88rem' }}
          />
          <button onClick={handleSend} className="btn btn-primary" style={{ padding: '10px 18px', borderRadius: '10px' }}>
            <Send size={16} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default MockInbox;
