import React, { useState, useEffect } from 'react';
import { CRMProvider, useCRM } from './context/CRMContext';
import Logo from './components/Logo';
import './App.css';

// Import Pages
import StorePage from './pages/StorePage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';

// Dashboards only
import AdminDashboard          from './dashboards/AdminDashboard';
import MarketingDashboard      from './dashboards/MarketingDashboard';
import AccountDashboard        from './dashboards/AccountDashboard';
import DesignDashboard         from './dashboards/DesignDashboard';
import DigitizerDashboard      from './dashboards/DigitizerDashboard';
import OrderManagementDashboard from './dashboards/OrderManagementDashboard';
import ProductionDashboard     from './dashboards/ProductionDashboard';
import DeliveryDashboard       from './dashboards/DeliveryDashboard';
import TelecallerDashboard     from './dashboards/TelecallerDashboard';
import VendorDashboard         from './dashboards/VendorDashboard';

/* ── colour tokens ──────────────────────────────────────────────── */
const P    = '#5B4EE8';
const PL   = '#EEF0FD';
const DARK  = '#111827';
const MID   = '#6B7280';
const BORDER = '#E5E7EB';



/* ════════════════════════════════════════════════════════════════ */
/*  MAIN APP ROUTER                                                 */
/* ════════════════════════════════════════════════════════════════ */
const AppRouter = () => {
  const { currentUser, logoutUser } = useCRM();
  const [viewState, setViewState] = useState(() => {
    const saved = localStorage.getItem('pallywear_user');
    if (saved) {
      try {
        const u = JSON.parse(saved);
        if (u && u.role !== 'customer') {
          return 'dashboard';
        }
      } catch (e) {}
    }
    return 'store';
  });

  useEffect(() => {
    if (!currentUser) {
      setViewState('store');
    } else if (currentUser.role !== 'customer') {
      setViewState('dashboard');
    } else {
      setViewState('store');
    }
  }, [currentUser]);

  const handleLoginSuccess = (user) => {
    if (user.role === 'customer') {
      setViewState('store');
    } else {
      setViewState('dashboard');
    }
  };

  const handleRegisterSuccess = (user) => {
    if (user.role === 'customer') {
      setViewState('store');
    } else {
      setViewState('dashboard');
    }
  };

  const handleNavLogout = () => {
    logoutUser();
    setViewState('store');
  };

  // Header Nav for customer storefront view
  const renderStoreHeader = () => {
    return (
      <header 
        className="glass-panel" 
        style={{ 
          height: '75px', 
          borderRadius: '0', 
          borderTop: 'none', 
          borderLeft: 'none', 
          borderRight: 'none',
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'space-between', 
          padding: '0 32px',
          borderBottom: '1px solid var(--border-color)',
          background: 'var(--bg-card)'
        }}
      >
        <div 
          onClick={() => setViewState('store')}
          style={{ display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer' }}
        >
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Logo size={32} />
          </div>
          <span style={{ fontSize: '1rem', fontWeight: 800, color: 'var(--text-primary)', letterSpacing: '-0.02em' }}>
            PALLYWEAR
          </span>
        </div>

        <div style={{ display: 'flex', alignItems: 'center', gap: '14px' }}>
          {currentUser && (
            <>
              {currentUser.role !== 'customer' && (
                <button 
                  onClick={() => setViewState('dashboard')}
                  className="btn btn-primary"
                  style={{ padding: '8px 16px', fontSize: '0.8rem', borderRadius: '8px', background: 'linear-gradient(135deg, #5B4EE8 0%, #3730A3 100%)', border: 'none' }}
                >
                  Staff Portal
                </button>
              )}
              <button 
                onClick={handleNavLogout}
                className="btn btn-danger"
                style={{ padding: '8px 16px', fontSize: '0.8rem', borderRadius: '8px' }}
              >
                Sign Out
              </button>
            </>
          )}
        </div>
      </header>
    );
  };

  if (viewState === 'dashboard' && currentUser && currentUser.role !== 'customer') {
    const handleLogout = () => { logoutUser(); setViewState('store'); };

    switch (currentUser.role) {
      case 'admin':           return <AdminDashboard           onLogout={handleLogout} />;
      case 'marketing':       return <MarketingDashboard       onLogout={handleLogout} />;
      case 'account':         return <AccountDashboard         onLogout={handleLogout} />;
      case 'design':
      case 'designer':        return <DesignDashboard          onLogout={handleLogout} />;
      case 'digitizer':       return <DigitizerDashboard       onLogout={handleLogout} />;
      case 'ordermanagement': return <OrderManagementDashboard onLogout={handleLogout} />;
      case 'production':      return <ProductionDashboard      onLogout={handleLogout} />;
      case 'delivery':        return <DeliveryDashboard        onLogout={handleLogout} />;
      case 'telecaller':      return <TelecallerDashboard      onLogout={handleLogout} />;
      case 'vendor':          return <VendorDashboard          onLogout={handleLogout} />;
      default:
        return (
          <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#F3F4F8', fontFamily: 'Inter, sans-serif' }}>
            <div style={{ textAlign: 'center' }}>
              <p style={{ color: '#6B7280', marginBottom: '16px' }}>No dashboard configured for role: <strong>{currentUser.role}</strong></p>
              <button onClick={handleLogout} style={{ padding: '10px 24px', background: '#5B4EE8', color: '#fff', border: 'none', borderRadius: '10px', fontWeight: 700, cursor: 'pointer' }}>
                Logout
              </button>
            </div>
          </div>
        );
    }
  }

  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
      {renderStoreHeader()}
      <div style={{ flex: 1, overflowY: 'auto' }}>
        {viewState === 'store' && <StorePage onNavigate={setViewState} />}
        {viewState === 'login' && <LoginPage onNavigate={setViewState} onLoginSuccess={handleLoginSuccess} />}
        {viewState === 'register' && <RegisterPage onNavigate={setViewState} onRegisterSuccess={handleRegisterSuccess} />}
      </div>
    </div>
  );
};

/* ════════════════════════════════════════════════════════════════ */
function App() {
  return (
    <CRMProvider>
      <AppRouter />
    </CRMProvider>
  );
}

export default App;
