  const processedCount = ordersList.filter(o => o.status === 'Production' || o.status === 'Delivery').length;
  const queueCount = ordersList.filter(o => o.status === 'Design' || o.status === 'Digitizing').length;
  const pendingInvoices = invoices.filter(inv => inv.status === 'Pending');

