import React, { useState } from 'react';
import { useCRM } from '../context/CRMContext';
import { Key, Mail, Info, ArrowRight } from 'lucide-react';
import Logo from '../components/Logo';

const LoginPage = ({ onNavigate, onLoginSuccess }) => {
  const { loginUser } = useCRM();
  
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [errorMsg, setErrorMsg] = useState('');

  // Sample pre-sets for testing
  const testUsers = [
    { label: 'Admin Staff', email: 'admin@pallywear.com', pass: 'admin123' },
    { label: 'Marketing Head', email: 'marketing@pallywear.com', pass: 'marketing123' },
    { label: 'Graphic Artist', email: 'designer@pallywear.com', pass: 'design123' },
    { label: 'Embroidery Specialist', email: 'digitizer@pallywear.com', pass: 'digitizer123' },
    { label: 'Standard Customer', email: 'customer@gmail.com', pass: 'customer123' }
  ];

  const handleQuickLogin = (emailPreset, passPreset) => {
    setEmail(emailPreset);
    setPassword(passPreset);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email || !password) return;

    try {
      setErrorMsg('');
      const loggedIn = await loginUser(email, password);
      if (onLoginSuccess) {
        onLoginSuccess(loggedIn);
      }
    } catch (err) {
      setErrorMsg(err.message || 'Login failed. Please check credentials.');
    }
  };

  return (
    <div className="auth-wrapper animate-fade-in">
      <div className="glass-panel auth-card" style={{ display: 'flex', flexDirection: 'column', gap: '24px', background: 'var(--bg-card)' }}>
        
        {/* Card Header */}
        <div style={{ textAlign: 'center' }}>
          <div style={{ 
            width: '46px', height: '46px', borderRadius: '12px', 
            background: 'linear-gradient(135deg, #5B4EE8 0%, #3730A3 100%)',
            display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
            boxShadow: '0 4px 14px rgba(91, 78, 232, 0.25)', marginBottom: '14px',
            color: 'var(--text-primary)'
          }}>
            <Logo size={24} color="white" />
          </div>
          <h2 style={{ fontSize: '1.4rem', fontWeight: 800, color: 'var(--text-primary)', letterSpacing: '-0.02em', margin: 0 }}>
            Welcome Back
          </h2>
          <p style={{ fontSize: '0.82rem', color: 'var(--text-secondary)', marginTop: '4px' }}>
            Access your Pallywear portal workspace
          </p>
        </div>

        {errorMsg && (
          <div style={{ padding: '10px 14px', background: 'rgba(244, 63, 94, 0.1)', border: '1px solid rgba(244, 63, 94, 0.3)', borderRadius: '8px', color: '#f43f5e', fontSize: '0.82rem', fontWeight: 500 }}>
            {errorMsg}
          </div>
        )}

        {/* Input Form */}
        <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
          <div className="form-group" style={{ marginBottom: 0 }}>
            <label className="form-label">Email Address</label>
            <div style={{ position: 'relative' }}>
              <Mail size={14} style={{ position: 'absolute', top: '14px', left: '14px', color: 'var(--text-muted)' }} />
              <input
                type="email"
                className="form-input"
                value={email}
                onChange={e => setEmail(e.target.value)}
                placeholder="e.g. admin@pallywear.com"
                style={{ paddingLeft: '40px', width: '100%' }}
                required
              />
            </div>
          </div>

          <div className="form-group" style={{ marginBottom: 0 }}>
            <label className="form-label">Security Password</label>
            <div style={{ position: 'relative' }}>
              <Key size={14} style={{ position: 'absolute', top: '14px', left: '14px', color: 'var(--text-muted)' }} />
              <input
                type="password"
                className="form-input"
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="••••••••"
                style={{ paddingLeft: '40px', width: '100%' }}
                required
              />
            </div>
          </div>

          <button type="submit" className="btn" style={{ height: '42px', marginTop: '4px', width: '100%', background: 'linear-gradient(135deg, #5B4EE8 0%, #3730A3 100%)', color: '#fff', border: 'none', boxShadow: '0 4px 14px rgba(91, 78, 232, 0.25)' }}>
            Sign In Portal <ArrowRight size={16} />
          </button>
        </form>

        <div style={{ textAlign: 'center', fontSize: '0.85rem' }}>
          <span style={{ color: 'var(--text-secondary)' }}>Don't have an account? </span>
          <button 
            onClick={() => onNavigate('register')}
            style={{ background: 'none', border: 'none', color: '#5B4EE8', fontWeight: 700, cursor: 'pointer', padding: 0 }}
          >
            Register Here
          </button>
        </div>

        {/* Quick Testing hints */}
        <div style={{ borderTop: '1px solid var(--border-color)', paddingTop: '20px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '6px', color: 'var(--text-secondary)', fontSize: '0.78rem', fontWeight: 600, marginBottom: '10px' }}>
            <Info size={12} style={{ color: 'var(--color-admin)' }} />
            Quick-Login Shortcuts for Testers
          </div>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
            {testUsers.map((preset, idx) => (
              <button
                key={idx}
                onClick={() => handleQuickLogin(preset.email, preset.pass)}
                style={{
                  padding: '8px 10px',
                  borderRadius: '6px',
                  border: '1px solid var(--border-color)',
                  background: 'transparent',
                  color: 'var(--text-secondary)',
                  fontSize: '0.72rem',
                  fontWeight: 600,
                  cursor: 'pointer',
                  textAlign: 'left',
                  transition: 'var(--transition-smooth)'
                }}
                onMouseEnter={e => {
                  e.currentTarget.style.borderColor = '#5B4EE8';
                  e.currentTarget.style.color = '#5B4EE8';
                  e.currentTarget.style.background = 'rgba(91, 78, 232, 0.05)';
                }}
                onMouseLeave={e => {
                  e.currentTarget.style.borderColor = 'var(--border-color)';
                  e.currentTarget.style.color = 'var(--text-secondary)';
                  e.currentTarget.style.background = 'transparent';
                }}
              >
                <div>{preset.label}</div>
                <div style={{ fontSize: '0.62rem', color: 'var(--text-muted)', fontFamily: 'monospace', textOverflow: 'ellipsis', overflow: 'hidden' }}>{preset.email}</div>
              </button>
            ))}
          </div>
        </div>

      </div>
    </div>
  );
};

export default LoginPage;
