import React, { useState } from 'react';
import Logo from '../components/Logo';
import { useCRM } from '../context/CRMContext';
import StatCard from '../components/StatCard';
import CustomChart from '../components/CustomChart';
import { Truck, CheckCircle, Navigation, Clock, Search, Bell, LogOut, Download } from 'lucide-react';

const DeliveryDashboard = ({ onLogout }) => {
  const { shipments = [], orders = [], updateShipmentStatus, deliveryCompleteOrder, toggleOrderHold, currentUser, logoutUser } = useCRM();

  const userAvatarUrl = currentUser?.name === 'Alex R.'
    ? "https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=facearea&facepad=2&w=256&h=256&q=80"
    : `https://ui-avatars.com/api/?name=${encodeURIComponent(currentUser?.name || 'Delivery')}&background=3b82f6&color=fff&bold=true`;

  const [showChat, setShowChat] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatMessages, setChatMessages] = useState([
    { id: 1, sender: 'Admin', text: 'Hi Delivery team, order #1002 has high priority dispatch status today.', time: '10:12 AM' },
    { id: 2, sender: 'Delivery', text: 'Got it. Handed over to courier partner. Tracking ID updated.', time: '10:15 AM' }
  ]);

  // Tabs navigation
  const [activeTab, setActiveTab] = useState('dashboard'); // 'dashboard' | 'deliveries' | 'gps'
  const [searchQuery, setSearchQuery] = useState('');
  const [expandedShipmentId, setExpandedShipmentId] = useState(null);
  const [balanceNotesMap, setBalanceNotesMap] = useState({});
  
  // Dropdowns
  const [showNotif, setShowNotif] = useState(false);
  const [showProfile, setShowProfile] = useState(false);

  const handleLogout = () => {
    logoutUser();
    if (onLogout) onLogout();
  };

  // Computations
  const inTransitCount = shipments.filter(s => s.status === 'In Transit' || s.status === 'Picked Up').length;
  const deliveredCount = shipments.filter(s => s.status === 'Delivered').length;

  const courierStats = [
    { label: 'DHL Express', value: shipments.filter(s => s.courier === 'DHL Express').length || 1 },
    { label: 'FedEx Ground', value: shipments.filter(s => s.courier === 'FedEx Ground').length || 2 },
    { label: 'UPS Air', value: shipments.filter(s => s.courier === 'UPS Air').length || 0 }
  ];

  // Search filter
  const queryLower = searchQuery.toLowerCase();
  const filteredShipments = shipments.filter(
    (ship) =>
      ship.id.toLowerCase().includes(queryLower) ||
      ship.orderId.toLowerCase().includes(queryLower) ||
      ship.courier.toLowerCase().includes(queryLower) ||
      ship.trackingNo.toLowerCase().includes(queryLower) ||
      ship.destination.toLowerCase().includes(queryLower) ||
      ship.status.toLowerCase().includes(queryLower)
  );

  const [isDarkMode, setIsDarkMode] = useState(() => document.body.classList.contains('dark-theme'));

  const handleThemeToggle = () => {
    const newMode = !isDarkMode;
    setIsDarkMode(newMode);
    if (newMode) {
      document.body.classList.add('dark-theme');
    } else {
      document.body.classList.remove('dark-theme');
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Carrier Workloads', icon: <Truck size={18} /> },
    { id: 'deliveries', label: 'Active Deliveries Queue', icon: <CheckCircle size={18} /> },
    { id: 'gps', label: 'Live GPS Coordinates', icon: <Navigation size={18} /> }
  ];

  return (
    <div className="app-container">
      {/* ── LEFT SIDEBAR ── */}
      <aside className="app-sidebar">
        <div className="sidebar-logo">
          <Logo size={24} color="var(--color-primary)" />
          <span className="sidebar-brand-name">PALLYWEAR</span>
        </div>
        
        <nav className="sidebar-nav">
          {navItems.map((item) => {
            const isActive = activeTab === item.id;
            return (
              <button
                key={item.id}
                onClick={() => { setActiveTab(item.id); setSearchQuery(''); }}
                className={`sidebar-link ${isActive ? 'active' : ''}`}
              >
                {item.icon}
                <span>{item.label}</span>
              </button>
            );
          })}
        </nav>
        
        <div className="sidebar-preferences">
          <div className="preferences-header">Preferences</div>
          <div className="dark-mode-toggle-row">
            <span>Dark Mode</span>
            <label className="switch">
              <input 
                type="checkbox" 
                checked={isDarkMode} 
                onChange={handleThemeToggle} 
              />
              <span className="slider"></span>
            </label>
          </div>
        </div>
      </aside>

      {/* ── RIGHT MAIN CONTENT ── */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        {/* Header inside right content pane */}
        <header style={{ 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center', 
          padding: '20px 24px', 
          borderBottom: '1px solid var(--border-color)',
          background: 'var(--bg-card)',
          flexShrink: 0
        }}>
          <div>
            <h1 style={{ fontSize: '1.25rem', fontWeight: 800, color: 'var(--text-primary)', margin: 0, textTransform: 'capitalize' }}>
              {activeTab.replace(/_/g, ' ')}
            </h1>
            <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: '2px' }}>
              Pallywear Delivery / <span style={{ color: 'var(--text-primary)', fontWeight: 600 }}>{activeTab.replace(/_/g, ' ')}</span>
            </div>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
            {/* Search Input */}
            <div style={{ position: 'relative' }}>
              <Search size={14} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
              <input
                type="text"
                placeholder="Search..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                style={{ 
                  paddingLeft: '32px', 
                  paddingRight: '12px', 
                  height: '36px', 
                  fontSize: '0.82rem', 
                  background: 'var(--bg-app)', 
                  border: '1px solid var(--border-color)', 
                  borderRadius: '18px', 
                  color: 'var(--text-primary)', 
                  width: '200px',
                  transition: 'var(--transition-smooth)'
                }}
              />
            </div>

            {/* Notification Bell */}
            <div style={{ position: 'relative' }}>
              <button 
                onClick={() => { setShowNotif(!showNotif); setShowProfile(false); }} 
                className="btn btn-outline" 
                style={{ width: '36px', height: '36px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 0 }}
              >
                <Bell size={16} />
              </button>
              {showNotif && (
                <div className="glass-panel animate-fade-in" style={{ position: 'absolute', right: 0, top: '44px', width: '280px', padding: '16px', zIndex: 1000 }}>
                  <div style={{ fontWeight: 700, fontSize: '0.88rem', marginBottom: '8px' }}>Notifications</div>
                  <div style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>System status normal. Active role: delivery</div>
                </div>
              )}
            </div>

            {/* Profile Dropdown */}
            <div style={{ position: 'relative' }}>
              <button 
                onClick={() => { setShowProfile(!showProfile); setShowNotif(false); }}
                style={{ 
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                  padding: '4px 12px 4px 6px',
                  borderRadius: '20px',
                  background: 'var(--bg-app)',
                  border: '1px solid var(--border-color)',
                  color: 'var(--text-primary)',
                  cursor: 'pointer'
                }}
              >
                <img 
                  src={userAvatarUrl}
                  alt={currentUser?.name || "User"}
                  style={{ width: '28px', height: '28px', borderRadius: '50%', objectFit: 'cover', border: '1px solid var(--border-color)' }}
                />
                <span style={{ fontSize: '0.82rem', fontWeight: 600 }}>{currentUser?.name || 'Staff'}</span>
              </button>
              
              {showProfile && (
                <div className="glass-panel animate-fade-in" style={{ position: 'absolute', right: 0, top: '44px', width: '220px', padding: '16px', zIndex: 1000, display: 'flex', flexDirection: 'column', gap: '8px' }}>
                  <div style={{ fontSize: '0.85rem', fontWeight: 800, color: 'var(--text-primary)' }}>{currentUser?.name || 'User Profile'}</div>
                  <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{currentUser?.email || 'delivery@pallywear.com'}</div>
                  <hr style={{ border: 'none', borderBottom: '1px solid var(--border-color)', margin: '8px 0' }} />
                  <button onClick={handleLogout} className="btn btn-danger" style={{ width: '100%', padding: '8px', fontSize: '0.78rem', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px' }}>
                    <LogOut size={12} /> Sign Out (Logout)
                  </button>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* Scrollable View Area */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '24px' }}>
          
          {/* TAB 1: LOGISTICS OVERVIEW */}
          {activeTab === 'dashboard' && (
            <div className="animate-fade-in" style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: '20px' }}>
                <StatCard 
                  title="Active Shipments" 
                  value={inTransitCount} 
                  subtext="Packages currently in transit" 
                  icon={Truck} 
                  color="delivery"
                />
                <StatCard 
                  title="Completed Deliveries" 
                  value={deliveredCount} 
                  subtext="Successful drop-offs" 
                  icon={CheckCircle} 
                  color="delivery"
                  trend={{ percentage: 14.1, isPositive: true }}
                />
                <StatCard 
                  title="Avg Dispatch Time" 
                  value="1.8 Days" 
                  subtext="Order packaging speed" 
                  icon={Clock} 
                  color="delivery"
                />
              </div>

              <div className="glass-panel" style={{ padding: '24px' }}>
                <h3 style={{ fontSize: '1.05rem', fontWeight: 700, marginBottom: '20px', color: 'var(--text-primary)' }}>Courier Share Distribution</h3>
                <CustomChart type="donut" data={courierStats} color="delivery" height={180} />
              </div>
            </div>
          )}

          {/* TAB 2: ACTIVE LOGISTICS DISPATCH REGISTER */}
          {activeTab === 'deliveries' && (
            <div className="animate-fade-in glass-panel glow-delivery" style={{ padding: '24px' }}>
              <h3 style={{ fontSize: '1.05rem', fontWeight: 700, marginBottom: '16px', color: 'var(--text-primary)' }}>Active Logistics Dispatch Register</h3>
              <div className="table-container">
                <table className="custom-table">
                  <thead>
                    <tr>
                      <th>Package ID</th>
                      <th>Order ID</th>
                      <th>Courier Partner</th>
                      <th>Tracking Number</th>
                      <th>Destination</th>
                      <th>ETA</th>
                      <th>Status</th>
                      <th style={{ textAlign: 'right' }}>Actions</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredShipments.map((ship) => {
                      const order = (orders || []).find(o => o.id === ship.orderId || o.id === ship.order_id);
                      const isExpanded = expandedShipmentId === ship.id;
                      const isHold = order?.is_hold === 1;

                      // Extraction helpers for specs
                      const material = order?.items?.match(/Material:\s*([^,;)]+)/)?.[1] || order?.details?.match(/Material:\s*([^,;)]+)/)?.[1] || 'Standard';
                      const color = order?.items?.match(/Color:\s*([^,;)]+)/)?.[1] || order?.details?.match(/Color:\s*([^,;)]+)/)?.[1] || 'Default';
                      
                      let sizeText = 'N/A';
                      try {
                        const parsed = JSON.parse(order?.sizeBreakdown);
                        if (Array.isArray(parsed)) {
                          const list = parsed.map(it => {
                            const formatGrps = [];
                            ['men', 'women', 'boys', 'girls'].forEach(g => {
                              if (it[g]) {
                                const s = Object.entries(it[g]).filter(([_, q]) => q && parseInt(q) > 0).map(([k, q]) => `${k}:${q}`).join(',');
                                if (s) formatGrps.push(`${g}(${s})`);
                              }
                            });
                            return `${it.category}: ${formatGrps.join(' | ')}`;
                          });
                          sizeText = list.join('; ');
                        }
                      } catch(e) {}

                      return (
                        <React.Fragment key={ship.id}>
                          <tr 
                            onClick={() => setExpandedShipmentId(isExpanded ? null : ship.id)}
                            style={{ cursor: 'pointer', borderBottom: '1px solid var(--border-color)' }}
                          >
                            <td style={{ fontWeight: 'bold' }}>{ship.id}</td>
                            <td>{ship.orderId}</td>
                            <td>{ship.courier}</td>
                            <td style={{ fontFamily: 'monospace' }}>{ship.trackingNo}</td>
                            <td style={{ fontSize: '0.85rem' }}>{ship.destination}</td>
                            <td>{ship.eta}</td>
                            <td>
                              <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
                                <span className={`badge ${
                                  ship.status === 'Delivered' ? 'badge-success' :
                                  ship.status === 'In Transit' ? 'badge-info' : 'badge-warning'
                                }`}>
                                  {ship.status}
                                </span>
                                {isHold && (
                                  <span style={{ fontSize: '0.65rem', background: '#fee2e2', color: '#ef4444', padding: '2px 6px', borderRadius: '4px', fontWeight: 800, alignSelf: 'flex-start' }}>
                                    ON HOLD
                                  </span>
                                )}
                              </div>
                            </td>
                            <td style={{ textAlign: 'right' }}>
                              <div style={{ display: 'flex', gap: '8px', justifyContent: 'flex-end', alignItems: 'center' }}>
                                <button
                                  onClick={(e) => { e.stopPropagation(); setExpandedShipmentId(isExpanded ? null : ship.id); }}
                                  className="btn btn-outline"
                                  style={{ padding: '6px 12px', fontSize: '0.75rem', borderRadius: '6px' }}
                                >
                                  {isExpanded ? 'Collapse' : 'Details'}
                                </button>
                                
                                <button
                                  onClick={(e) => {
                                    e.stopPropagation();
                                    if (order) {
                                      toggleOrderHold(order.id, !isHold);
                                    }
                                  }}
                                  style={{
                                    padding: '6px 12px',
                                    fontSize: '0.75rem',
                                    borderRadius: '6px',
                                    background: isHold ? '#10b981' : '#f59e0b',
                                    color: '#ffffff',
                                    border: 'none',
                                    fontWeight: 700,
                                    cursor: 'pointer'
                                  }}
                                >
                                  {isHold ? 'Resume' : 'Hold'}
                                </button>
                              </div>
                            </td>
                          </tr>

                          {isExpanded && (
                            <tr>
                              <td colSpan="8" style={{ padding: '16px', background: 'rgba(255,255,255,0.02)', borderBottom: '1px solid var(--border-color)' }}>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '14px', textAlign: 'left' }}>
                                  
                                  {/* Order & Customer Metadata */}
                                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '16px', background: 'rgba(0,0,0,0.1)', padding: '14px', borderRadius: '10px' }}>
                                    <div>
                                      <span style={{ display: 'block', fontSize: '0.72rem', fontWeight: 700, color: 'var(--text-secondary)' }}>CUSTOMER NAME</span>
                                      <span style={{ fontSize: '0.85rem', fontWeight: 800, color: 'var(--text-primary)' }}>{order?.customerName || order?.clientName || 'N/A'}</span>
                                    </div>
                                    <div>
                                      <span style={{ display: 'block', fontSize: '0.72rem', fontWeight: 700, color: 'var(--text-secondary)' }}>PHONE NUMBER</span>
                                      <span style={{ fontSize: '0.85rem', fontWeight: 800, color: 'var(--text-primary)' }}>{order?.customerPhone || order?.customer_phone || 'N/A'}</span>
                                    </div>
                                    <div>
                                      <span style={{ display: 'block', fontSize: '0.72rem', fontWeight: 700, color: 'var(--text-secondary)' }}>COLOUR / SPEC</span>
                                      <span style={{ fontSize: '0.85rem', fontWeight: 800, color: 'var(--text-primary)' }}>{color}</span>
                                    </div>
                                    <div>
                                      <span style={{ display: 'block', fontSize: '0.72rem', fontWeight: 700, color: 'var(--text-secondary)' }}>QTY ORDERED</span>
                                      <span style={{ fontSize: '0.85rem', fontWeight: 800, color: 'var(--text-primary)' }}>{order?.quantity || 0} Units</span>
                                    </div>
                                    <div>
                                      <span style={{ display: 'block', fontSize: '0.72rem', fontWeight: 700, color: 'var(--text-secondary)' }}>MATERIAL</span>
                                      <span style={{ fontSize: '0.85rem', fontWeight: 800, color: 'var(--text-primary)' }}>{material}</span>
                                    </div>
                                    <div style={{ gridColumn: 'span 2' }}>
                                      <span style={{ display: 'block', fontSize: '0.72rem', fontWeight: 700, color: 'var(--text-secondary)' }}>SIZES SPECIFICATION</span>
                                      <span style={{ fontSize: '0.8rem', fontWeight: 700, color: 'var(--text-primary)' }}>{sizeText}</span>
                                    </div>
                                    <div>
                                      <span style={{ display: 'block', fontSize: '0.72rem', fontWeight: 700, color: 'var(--text-secondary)' }}>BALANCE AMOUNT</span>
                                      <span style={{ fontSize: '0.85rem', fontWeight: 800, color: '#f43f5e' }}>₹{(order?.balanceAmount || 0).toLocaleString('en-IN')}</span>
                                    </div>
                                  </div>

                                  {/* Clickable Google Maps Address */}
                                  <div>
                                    <span style={{ display: 'block', fontSize: '0.72rem', fontWeight: 700, color: 'var(--text-secondary)', marginBottom: '4px' }}>DELIVERY DESTINATION ADDRESS</span>
                                    <a 
                                      href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(order?.address || order?.customerAddress || ship.destination)}`} 
                                      target="_blank" 
                                      rel="noopener noreferrer" 
                                      style={{ color: 'var(--color-delivery)', fontWeight: 800, textDecoration: 'none', display: 'inline-flex', alignItems: 'center', gap: '6px', fontSize: '0.85rem' }}
                                    >
                                      📍 {order?.address || order?.customerAddress || ship.destination} (Click to open in Google Maps ↗)
                                    </a>
                                  </div>

                                  {/* Balance Notes Input and Action */}
                                  <div style={{ borderTop: '1px solid rgba(255,255,255,0.08)', paddingTop: '12px' }}>
                                    <label style={{ display: 'block', fontSize: '0.8rem', fontWeight: 700, color: 'var(--text-secondary)', marginBottom: '6px' }}>Balance Amount Received Details</label>
                                    <textarea
                                      rows="2"
                                      placeholder="Enter cash details, transaction IDs or UPI reference details..."
                                      value={balanceNotesMap[order?.id] || ''}
                                      onChange={(e) => setBalanceNotesMap(prev => ({ ...prev, [order?.id]: e.target.value }))}
                                      style={{ width: '100%', minHeight: '60px', padding: '10px', borderRadius: '8px', border: '1px solid var(--border-color)', background: 'rgba(0,0,0,0.2)', color: 'var(--text-primary)', outline: 'none', fontSize: '0.8rem' }}
                                    />
                                    
                                    <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: '12px' }}>
                                      {isHold ? (
                                        <span style={{ fontSize: '0.8rem', color: '#f59e0b', fontWeight: 700 }}>
                                          Shipment is ON HOLD. Resume order to complete delivery.
                                        </span>
                                      ) : ship.status !== 'Delivered' ? (
                                        <button
                                          onClick={() => {
                                            if (order) {
                                              deliveryCompleteOrder(order.id, balanceNotesMap[order.id] || '');
                                              setExpandedShipmentId(null);
                                            }
                                          }}
                                          className="btn btn-success"
                                          style={{ padding: '8px 18px', fontSize: '0.8rem', borderRadius: '8px', fontWeight: 700 }}
                                        >
                                          ✓ Complete Delivery
                                        </button>
                                      ) : (
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '4px', color: '#10b981', fontSize: '0.85rem', fontWeight: 600 }}>
                                          ✓ Completed (Delivered)
                                        </div>
                                      )}
                                    </div>
                                  </div>

                                </div>
                              </td>
                            </tr>
                          )}
                        </React.Fragment>
                      );
                    })}
                    {filteredShipments.length === 0 && (
                      <tr>
                        <td colSpan="8" style={{ textAlign: 'center', color: 'var(--text-muted)', padding: '24px' }}>
                          No packages found matching query.
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* TAB 3: LIVE GPS FLEET VIEWPORT */}
          {activeTab === 'gps' && (
            <div className="animate-fade-in glass-panel glow-delivery" style={{ padding: '24px' }}>
              <h3 style={{ fontSize: '1.05rem', fontWeight: 700, marginBottom: '16px', color: 'var(--text-primary)' }}>Live GPS Fleet Viewport</h3>
              
              <div style={{
                height: '400px',
                background: 'rgba(0,0,0,0.4)',
                borderRadius: '12px',
                border: '1px solid var(--border-color)',
                position: 'relative',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                justifyContent: 'center',
                color: 'var(--text-muted)',
                gap: '12px'
              }}>
                <Navigation size={48} style={{ transform: 'rotate(45deg)', color: 'var(--color-delivery)', animation: 'bounce 2s infinite' }} />
                <span style={{ fontSize: '1rem', fontWeight: 600, color: 'var(--text-primary)' }}>Real-time vehicle tracking simulation</span>
                <span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Denver Center Active | DHL-102 Dispatch</span>
                
                {/* Mock GPS coordinate overlay */}
                <div style={{
                  position: 'absolute',
                  bottom: '20px',
                  left: '20px',
                  background: 'rgba(0,0,0,0.8)',
                  padding: '10px 14px',
                  borderRadius: '6px',
                  border: '1px solid var(--border-color)',
                  fontFamily: 'monospace',
                  fontSize: '0.75rem',
                  color: 'var(--text-primary)',
                  display: 'flex',
                  flexDirection: 'column',
                  gap: '4px'
                }}>
                  <div>LAT: 39.7392° N</div>
                  <div>LON: 104.9903° W</div>
                  <div style={{ color: 'var(--color-delivery)' }}>STATUS: Fleet Route Nominal</div>
                </div>
              </div>
            </div>
          )}

        </div>

      </div>

      {/* Floating Chat Icon (matching bottom right of mockup) */}
      <div 
        onClick={() => setShowChat(!showChat)}
        style={{ position: 'fixed', bottom: '24px', right: '24px', width: '48px', height: '48px', borderRadius: '50%', background: '#0f172a', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 12px rgba(0,0,0,0.15)', cursor: 'pointer', zIndex: 9999 }}
      >
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#ffffff" strokeWidth="2">
          <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
        </svg>
      </div>

      {/* Floating Interactive Chat Drawer */}
      {showChat && (
        <div style={{
          position: 'fixed',
          bottom: '84px',
          right: '24px',
          width: '320px',
          height: '400px',
          background: '#ffffff',
          border: '1px solid #cbd5e1',
          borderRadius: '16px',
          boxShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.1)',
          display: 'flex',
          flexDirection: 'column',
          zIndex: 99999
        }}>
          {/* Header */}
          <div style={{ padding: '12px 16px', background: '#0f172a', borderTopLeftRadius: '16px', borderTopRightRadius: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', color: '#ffffff' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
              <span style={{ width: '8px', height: '8px', borderRadius: '50%', background: '#10b981', display: 'inline-block' }}></span>
              <span style={{ fontSize: '0.85rem', fontWeight: 800 }}>CRM Staff Chat</span>
            </div>
            <button onClick={() => setShowChat(false)} style={{ background: 'transparent', border: 'none', color: '#ffffff', cursor: 'pointer', fontSize: '0.85rem' }}>✕</button>
          </div>

          {/* Messages Body */}
          <div style={{ flex: 1, padding: '12px', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '8px', background: '#f8fafc' }}>
            {chatMessages.map(msg => (
              <div key={msg.id} style={{ alignSelf: msg.sender === 'Delivery' ? 'flex-end' : 'flex-start', maxWidth: '80%' }}>
                <div style={{ fontSize: '0.7rem', color: '#64748b', marginBottom: '2px', textAlign: msg.sender === 'Delivery' ? 'right' : 'left' }}>
                  {msg.sender} · {msg.time}
                </div>
                <div style={{
                  padding: '8px 12px',
                  borderRadius: '12px',
                  background: msg.sender === 'Delivery' ? '#3b82f6' : '#ffffff',
                  color: msg.sender === 'Delivery' ? '#ffffff' : '#0f172a',
                  border: msg.sender === 'Delivery' ? 'none' : '1px solid #cbd5e1',
                  fontSize: '0.8rem',
                  lineHeight: '1.4'
                }}>
                  {msg.text}
                </div>
              </div>
            ))}
          </div>

          {/* Footer Input */}
          <form 
            onSubmit={(e) => {
              e.preventDefault();
              if (!chatInput.trim()) return;
              const newMsg = {
                id: Date.now(),
                sender: 'Delivery',
                text: chatInput.trim(),
                time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
              };
              setChatMessages([...chatMessages, newMsg]);
              setChatInput('');
            }}
            style={{ padding: '8px 12px', borderTop: '1px solid #cbd5e1', display: 'flex', gap: '8px', background: '#ffffff', borderBottomLeftRadius: '16px', borderBottomRightRadius: '16px' }}
          >
            <input
              type="text"
              placeholder="Type a message..."
              value={chatInput}
              onChange={(e) => setChatInput(e.target.value)}
              style={{ flex: 1, border: '1px solid #cbd5e1', borderRadius: '20px', padding: '6px 12px', fontSize: '0.8rem', outline: 'none', color: '#0f172a' }}
            />
            <button type="submit" style={{ background: '#3b82f6', color: '#ffffff', border: 'none', borderRadius: '50%', width: '28px', height: '28px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', fontSize: '0.78rem', fontWeight: 800 }}>
              ➔
            </button>
          </form>
        </div>
      )}

    </div>
  );
};

export default DeliveryDashboard;
