import React, { useState } from 'react';

const CustomChart = ({ type = 'line', data = [], height = 200, color = 'production' }) => {
  const [hoveredIndex, setHoveredIndex] = useState(null);
  const chartId = React.useId().replace(/:/g, '-'); // Web safe ID for SVG definitions
  
  if (!data || data.length === 0) {
    return (
      <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)' }}>
        No data available
      </div>
    );
  }

  const accentColor = `var(--color-${color})`;

  // 1. DONUT CHART
  if (type === 'donut') {
    const total = data.reduce((acc, d) => acc + d.value, 0);
    if (total === 0) {
      return (
        <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', flex: 1 }}>
          No data available for this range
        </div>
      );
    }
    let cumulativePercent = 0;

    const getCoordinatesForPercent = (percent) => {
      const x = Math.cos(2 * Math.PI * percent);
      const y = Math.sin(2 * Math.PI * percent);
      return [x, y];
    };

    const segments = data.map((d, index) => {
      const percent = d.value / total;
      const startPercent = cumulativePercent;
      cumulativePercent += percent;

      const [startX, startY] = getCoordinatesForPercent(startPercent);
      const [endX, endY] = getCoordinatesForPercent(cumulativePercent);

      const largeArcFlag = percent > 0.5 ? 1 : 0;

      // Map segments to SVG path
      // Scale coordinates from [-1, 1] to [10, 90] within 100x100 viewBox
      const radius = 35;
      const cx = 50;
      const cy = 50;

      const x1 = cx + radius * startX;
      const y1 = cy + radius * startY;
      const x2 = cx + radius * endX;
      const y2 = cy + radius * endY;

      const pathData = [
        `M ${x1} ${y1}`,
        `A ${radius} ${radius} 0 ${largeArcFlag} 1 ${x2} ${y2}`
      ].join(' ');

      // Color scheme for donut segments based on role accent
      const segmentColors = [
        `var(--color-${color})`,
        `rgba(${color === 'marketing' ? '6,182,214' : color === 'account' ? '16,185,129' : '59,130,246'}, 0.75)`,
        `rgba(${color === 'marketing' ? '6,182,214' : color === 'account' ? '16,185,129' : '59,130,246'}, 0.5)`,
        `rgba(${color === 'marketing' ? '6,182,214' : color === 'account' ? '16,185,129' : '59,130,246'}, 0.25)`,
        'rgba(255,255,255,0.1)'
      ];

      return {
        pathData,
        color: segmentColors[index % segmentColors.length],
        label: d.label,
        value: d.value,
        percentage: Math.round(percent * 100)
      };
    });

    return (
      <div style={{ display: 'flex', alignItems: 'center', gap: '20px', height }}>
        <div style={{ position: 'relative', width: `${height}px`, height: `${height}px` }}>
          <svg viewBox="0 0 100 100" style={{ transform: 'rotate(-90deg)', width: '100%', height: '100%' }}>
            {segments.map((seg, index) => (
              <path
                key={index}
                d={seg.pathData}
                fill="transparent"
                stroke={seg.color}
                strokeWidth={hoveredIndex === index ? '12' : '9'}
                style={{ 
                  cursor: 'pointer',
                  transition: 'all 0.2s ease-in-out'
                }}
                onMouseEnter={() => setHoveredIndex(index)}
                onMouseLeave={() => setHoveredIndex(null)}
              />
            ))}
          </svg>
          <div style={{ 
            position: 'absolute', 
            top: 0, left: 0, right: 0, bottom: 0,
            display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center'
          }}>
            {hoveredIndex !== null ? (
              <>
                <span style={{ fontSize: '1.25rem', fontWeight: 800, color: 'var(--text-primary)' }}>
                  {segments[hoveredIndex].percentage}%
                </span>
                <span style={{ fontSize: '0.7rem', color: 'var(--text-muted)', textTransform: 'uppercase', textAlign: 'center', padding: '0 8px' }}>
                  {segments[hoveredIndex].label}
                </span>
              </>
            ) : (
              <>
                <span style={{ fontSize: '1.2rem', fontWeight: 800, color: 'var(--text-primary)' }}>
                  {total}
                </span>
                <span style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>
                  Total Units
                </span>
              </>
            )}
          </div>
        </div>

        {/* Legend */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', flex: 1, maxHeight: '100%', overflowY: 'auto' }}>
          {segments.map((seg, index) => (
            <div 
              key={index} 
              style={{ 
                display: 'flex', 
                alignItems: 'center', 
                justifyContent: 'space-between',
                padding: '4px 8px',
                borderRadius: '6px',
                background: hoveredIndex === index ? 'rgba(255,255,255,0.03)' : 'transparent',
                cursor: 'pointer',
                transition: 'var(--transition-smooth)'
              }}
              onMouseEnter={() => setHoveredIndex(index)}
              onMouseLeave={() => setHoveredIndex(null)}
            >
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                <span style={{ width: '8px', height: '8px', borderRadius: '50%', backgroundColor: seg.color }}></span>
                <span style={{ fontSize: '0.8rem', color: hoveredIndex === index ? 'white' : 'var(--text-secondary)', fontWeight: 500 }}>
                  {seg.label}
                </span>
              </div>
              <span style={{ fontSize: '0.8rem', fontWeight: 700, color: 'var(--text-primary)' }}>
                {seg.value}
              </span>
            </div>
          ))}
        </div>
      </div>
    );
  }

  // Width calculation for Line and Bar charts
  const paddingX = 40;
  const paddingY = 30;
  const chartWidth = 500;
  const chartHeight = 200;
  const values = data.map((d) => d.value);
  const maxValue = Math.max(...values, 1) * 1.15; // Give headroom

  const getX = (index) => paddingX + (index * (chartWidth - paddingX * 2)) / (data.length - 1 || 1);
  const getY = (value) => chartHeight - paddingY - (value * (chartHeight - paddingY * 2)) / maxValue;

  // 2. BAR CHART
  if (type === 'bar') {
    const barWidth = Math.max(10, ((chartWidth - paddingX * 2) / data.length) * 0.6);
    
    return (
      <div style={{ width: '100%', position: 'relative' }}>
        <svg viewBox={`0 0 ${chartWidth} ${chartHeight}`} style={{ width: '100%', height }}>
          <defs>
            <linearGradient id={`barGrad-${chartId}`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={accentColor} />
              <stop offset="100%" stopColor="rgba(59, 130, 246, 0.05)" />
            </linearGradient>
          </defs>

          {/* Grid lines */}
          {[0, 0.25, 0.5, 0.75, 1].map((ratio, index) => {
            const yVal = chartHeight - paddingY - ratio * (chartHeight - paddingY * 2);
            return (
              <line
                key={index}
                x1={paddingX}
                y1={yVal}
                x2={chartWidth - paddingX}
                y2={yVal}
                stroke="rgba(255, 255, 255, 0.04)"
                strokeDasharray="4 4"
              />
            );
          })}

          {/* Render Bars */}
          {data.map((d, index) => {
            const x = getX(index) - barWidth / 2;
            const y = getY(d.value);
            const heightVal = chartHeight - paddingY - y;

            return (
              <g key={index}>
                {/* Visual Bar */}
                <rect
                  x={x}
                  y={y}
                  width={barWidth}
                  height={Math.max(2, heightVal)}
                  rx="4"
                  fill={`url(#barGrad-${chartId})`}
                  stroke={accentColor}
                  strokeWidth={hoveredIndex === index ? '1.5' : '0'}
                  style={{ cursor: 'pointer', transition: 'all 0.2s' }}
                  onMouseEnter={() => setHoveredIndex(index)}
                  onMouseLeave={() => setHoveredIndex(null)}
                />
                
                {/* Value Hover Tooltip Trigger */}
                {hoveredIndex === index && (
                  <rect
                    x={x - 10}
                    y={y - 30}
                    width={barWidth + 20}
                    height="20"
                    fill="rgba(0,0,0,0.85)"
                    rx="4"
                  />
                )}
                {hoveredIndex === index && (
                  <text
                    x={x + barWidth / 2}
                    y={y - 17}
                    fill="white"
                    fontSize="9"
                    fontWeight="bold"
                    textAnchor="middle"
                  >
                    {d.value}
                  </text>
                )}

                {/* X Axis Label */}
                <text
                  x={getX(index)}
                  y={chartHeight - 8}
                  fill="var(--text-muted)"
                  fontSize="8.5"
                  fontWeight="600"
                  textAnchor="middle"
                >
                  {d.label}
                </text>
              </g>
            );
          })}
        </svg>
      </div>
    );
  }

  // 3. LINE CHART (Default)
  const points = data.map((d, i) => `${getX(i)},${getY(d.value)}`).join(' ');
  
  // Create area path under line chart for glow fill
  const areaPoints = data.length > 0 
    ? `${getX(0)},${chartHeight - paddingY} ${points} ${getX(data.length - 1)},${chartHeight - paddingY}`
    : '';

  return (
    <div style={{ width: '100%', position: 'relative' }}>
      <svg viewBox={`0 0 ${chartWidth} ${chartHeight}`} style={{ width: '100%', height }}>
        <defs>
          <linearGradient id={`areaGrad-${chartId}`} x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={accentColor} stopOpacity="0.25" />
            <stop offset="100%" stopColor={accentColor} stopOpacity="0" />
          </linearGradient>
          <linearGradient id={`lineGrad-${chartId}`} x1="0" y1="0" x2="1" y2="0">
            <stop offset="0%" stopColor={accentColor} />
            <stop offset="100%" stopColor="#3b82f6" />
          </linearGradient>
        </defs>

        {/* Grid lines */}
        {[0, 0.25, 0.5, 0.75, 1].map((ratio, index) => {
          const yVal = chartHeight - paddingY - ratio * (chartHeight - paddingY * 2);
          return (
            <line
              key={index}
              x1={paddingX}
              y1={yVal}
              x2={chartWidth - paddingX}
              y2={yVal}
              stroke="rgba(255, 255, 255, 0.03)"
            />
          );
        })}

        {/* Area Gradient Shading */}
        {areaPoints && (
          <polygon
            points={areaPoints}
            fill={`url(#areaGrad-${chartId})`}
          />
        )}

        {/* Glowing Spline Line */}
        <polyline
          fill="none"
          stroke={`url(#lineGrad-${chartId})`}
          strokeWidth="3.5"
          strokeLinecap="round"
          strokeLinejoin="round"
          points={points}
        />

        {/* Interactive Data Dots */}
        {data.map((d, index) => {
          const cx = getX(index);
          const cy = getY(d.value);
          const isHovered = hoveredIndex === index;

          return (
            <g key={index}>
              {/* Invisible interactive hover trigger zone */}
              <circle
                cx={cx}
                cy={cy}
                r="12"
                fill="transparent"
                style={{ cursor: 'pointer' }}
                onMouseEnter={() => setHoveredIndex(index)}
                onMouseLeave={() => setHoveredIndex(null)}
              />
              
              {/* Visual dot */}
              <circle
                cx={cx}
                cy={cy}
                r={isHovered ? '6' : '3.5'}
                fill="#090d16"
                stroke={isHovered ? 'white' : accentColor}
                strokeWidth="2.5"
                style={{ transition: 'all 0.15s ease-out', pointerEvents: 'none' }}
              />

              {/* X Axis Label */}
              <text
                x={cx}
                y={chartHeight - 8}
                fill="var(--text-muted)"
                fontSize="8.5"
                fontWeight="600"
                textAnchor="middle"
              >
                {d.label}
              </text>
            </g>
          );
        })}
      </svg>

      {/* Floating HTML Tooltip overlay */}
      {hoveredIndex !== null && (
        <div style={{
          position: 'absolute',
          top: `${getY(data[hoveredIndex].value) - 40}px`,
          left: `calc(${(getX(hoveredIndex) / chartWidth) * 100}% - 50px)`,
          width: '100px',
          background: 'rgba(9, 13, 22, 0.9)',
          backdropFilter: 'blur(4px)',
          border: `1px solid ${accentColor}`,
          borderRadius: '6px',
          padding: '4px 8px',
          textAlign: 'center',
          boxShadow: '0 4px 12px rgba(0,0,0,0.5)',
          pointerEvents: 'none',
          zIndex: 10,
          animation: 'fadeInUp 0.15s ease'
        }}>
          <div style={{ fontSize: '0.65rem', color: 'var(--text-secondary)', textTransform: 'uppercase' }}>
            {data[hoveredIndex].label}
          </div>
          <div style={{ fontSize: '0.85rem', fontWeight: 800, color: 'var(--text-primary)' }}>
            {data[hoveredIndex].value}
          </div>
        </div>
      )}
    </div>
  );
};

export default CustomChart;
