import React, { useState } from 'react';
import { Package, Plus, ClipboardList, Trash2, CheckCircle2, AlertTriangle } from 'lucide-react';

const INITIAL_INVENTORY = [
  { id: 'INV-001', category: 'Oversized Hoodie', material: 'Terry Cotton', colour: 'Black', qty: { S: 120, M: 250, L: 180, XL: 90, XXL: 40 }, status: 'In Stock' },
  { id: 'INV-002', category: 'Oversized Hoodie', material: 'Terry Cotton', colour: 'White', qty: { S: 80, M: 110, L: 140, XL: 60, XXL: 20 }, status: 'In Stock' },
  { id: 'INV-003', category: 'T-Shirt Crewneck', material: 'Affordable Cotton', colour: 'Red', qty: { S: 15, M: 22, L: 12, XL: 8, XXL: 3 }, status: 'Low Stock' },
  { id: 'INV-004', category: 'T-Shirt Crewneck', material: 'Economy Cotton', colour: 'Navy', qty: { S: 5, M: 2, L: 4, XL: 0, XXL: 0 }, status: 'Restock Required' },
  { id: 'INV-005', category: 'Polo Shirt', material: 'Feathery Cotton', colour: 'Lilac', qty: { S: 50, M: 75, L: 60, XL: 30, XXL: 15 }, status: 'In Stock' },
  { id: 'INV-006', category: 'Sport Jersey', material: 'Dot Knit 190', colour: 'Royal Blue', qty: { S: 200, M: 350, L: 280, XL: 150, XXL: 70 }, status: 'In Stock' }
];

const MockInventory = ({ defaultTab = 'view' }) => {
  const [activeTab, setActiveTab] = useState(defaultTab);
  const [stock, setStock] = useState(INITIAL_INVENTORY);
  const [successMsg, setSuccessMsg] = useState('');

  // Form states
  const [category, setCategory] = useState('Oversized Hoodie');
  const [material, setMaterial] = useState('Terry Cotton');
  const [colour, setColour] = useState('Black');
  const [sizes, setSizes] = useState({ S: '', M: '', L: '', XL: '', XXL: '' });

  const handleAddStock = (e) => {
    e.preventDefault();
    const newId = `INV-${String(stock.length + 1).padStart(3, '0')}`;
    
    // Parse sizes
    const qtyParsed = {
      S: parseInt(sizes.S || 0),
      M: parseInt(sizes.M || 0),
      L: parseInt(sizes.L || 0),
      XL: parseInt(sizes.XL || 0),
      XXL: parseInt(sizes.XXL || 0)
    };

    const totalQty = Object.values(qtyParsed).reduce((a, b) => a + b, 0);
    let status = 'In Stock';
    if (totalQty === 0) status = 'Restock Required';
    else if (totalQty < 80) status = 'Low Stock';

    const newItem = {
      id: newId,
      category,
      material,
      colour,
      qty: qtyParsed,
      status
    };

    setStock([newItem, ...stock]);
    setSizes({ S: '', M: '', L: '', XL: '', XXL: '' });
    setSuccessMsg(`Inventory item ${newId} registered successfully!`);
    setTimeout(() => setSuccessMsg(''), 4000);
  };

  const getStatusBadge = (status) => {
    switch (status) {
      case 'In Stock':
        return (
          <span style={{ 
            background: 'rgba(16, 185, 129, 0.1)', 
            color: '#10b981', 
            border: '1px solid rgba(16, 185, 129, 0.2)',
            fontSize: '0.72rem', 
            fontWeight: 700, 
            padding: '3px 8px', 
            borderRadius: '4px',
            display: 'inline-flex',
            alignItems: 'center',
            gap: '4px'
          }}>
            <CheckCircle2 size={12} /> In Stock
          </span>
        );
      case 'Low Stock':
        return (
          <span style={{ 
            background: 'rgba(245, 158, 11, 0.1)', 
            color: '#f59e0b', 
            border: '1px solid rgba(245, 158, 11, 0.2)',
            fontSize: '0.72rem', 
            fontWeight: 700, 
            padding: '3px 8px', 
            borderRadius: '4px',
            display: 'inline-flex',
            alignItems: 'center',
            gap: '4px'
          }}>
            <AlertTriangle size={12} /> Low Stock
          </span>
        );
      case 'Restock Required':
      default:
        return (
          <span style={{ 
            background: 'rgba(239, 68, 68, 0.1)', 
            color: '#ef4444', 
            border: '1px solid rgba(239, 68, 68, 0.2)',
            fontSize: '0.72rem', 
            fontWeight: 800, 
            padding: '3px 8px', 
            borderRadius: '4px',
            display: 'inline-flex',
            alignItems: 'center',
            gap: '4px'
          }}>
            <AlertTriangle size={12} /> Restock Required
          </span>
        );
    }
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      
      {/* ── Sub Toggler ── */}
      <div style={{ display: 'flex', gap: '12px', borderBottom: '1px solid var(--border-color)', paddingBottom: '10px' }}>
        <button 
          onClick={() => { setActiveTab('view'); setSuccessMsg(''); }}
          style={{
            background: 'transparent',
            border: 'none',
            borderBottom: activeTab === 'view' ? '3px solid var(--color-marketing, #bf00af)' : '3px solid transparent',
            color: activeTab === 'view' ? 'var(--text-primary)' : 'var(--text-secondary)',
            padding: '8px 16px',
            fontWeight: 700,
            fontSize: '0.9rem',
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            transition: 'all 0.2s'
          }}
        >
          <ClipboardList size={16} /> View Stock Levels
        </button>
        <button 
          onClick={() => { setActiveTab('add'); setSuccessMsg(''); }}
          style={{
            background: 'transparent',
            border: 'none',
            borderBottom: activeTab === 'add' ? '3px solid var(--color-marketing, #bf00af)' : '3px solid transparent',
            color: activeTab === 'add' ? 'var(--text-primary)' : 'var(--text-secondary)',
            padding: '8px 16px',
            fontWeight: 700,
            fontSize: '0.9rem',
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            transition: 'all 0.2s'
          }}
        >
          <Plus size={16} /> Add Stock Item
        </button>
      </div>

      {successMsg && (
        <div style={{ padding: '12px 16px', background: 'rgba(16,185,129,0.1)', border: '1px solid rgba(16,185,129,0.3)', borderRadius: '8px', color: '#10b981', fontSize: '0.85rem', fontWeight: 600 }}>
          {successMsg}
        </div>
      )}

      {/* ── VIEW TAB ── */}
      {activeTab === 'view' && (
        <div className="glass-panel" style={{ padding: '24px' }}>
          <h3 style={{ fontSize: '1.05rem', fontWeight: 800, color: 'var(--text-primary)', marginBottom: '16px' }}>
            Warehouse Inventory Stock Ledger
          </h3>
          
          <div className="table-container">
            <table className="custom-table">
              <thead>
                <tr>
                  <th>SKU ID</th>
                  <th>Category</th>
                  <th>Material Component</th>
                  <th>Colour</th>
                  <th>Size Quantities</th>
                  <th>Total Pcs</th>
                  <th>Inventory Status</th>
                </tr>
              </thead>
              <tbody>
                {stock.map(item => {
                  const total = Object.values(item.qty).reduce((a, b) => a + b, 0);
                  return (
                    <tr key={item.id}>
                      <td style={{ fontWeight: 'bold' }}>{item.id}</td>
                      <td>{item.category}</td>
                      <td>{item.material}</td>
                      <td>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                          <span style={{ 
                            width: '12px', 
                            height: '12px', 
                            borderRadius: '50%', 
                            background: item.colour.toLowerCase(), 
                            border: '1px solid var(--border-color)',
                            display: 'inline-block' 
                          }} />
                          {item.colour}
                        </div>
                      </td>
                      <td>
                        <div style={{ fontSize: '0.78rem', display: 'flex', gap: '10px' }}>
                          {Object.entries(item.qty).map(([sz, q]) => (
                            <span key={sz} style={{ color: q === 0 ? 'var(--text-muted)' : 'var(--text-primary)' }}>
                              <strong>{sz}:</strong> {q}
                            </span>
                          ))}
                        </div>
                      </td>
                      <td style={{ fontWeight: 700 }}>{total}</td>
                      <td>{getStatusBadge(item.status)}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* ── ADD TAB ── */}
      {activeTab === 'add' && (
        <div className="glass-panel glow-marketing" style={{ padding: '24px' }}>
          <h3 style={{ fontSize: '1.05rem', fontWeight: 800, color: 'var(--text-primary)', marginBottom: '18px', display: 'flex', alignItems: 'center', gap: '8px' }}>
            <Package size={18} style={{ color: 'var(--color-marketing, #bf00af)' }} /> Add New Inventory Stock
          </h3>
          <form onSubmit={handleAddStock} style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '16px' }}>
              <div className="form-group" style={{ marginBottom: 0 }}>
                <label className="form-label">Product Category *</label>
                <select className="form-input" value={category} onChange={e => setCategory(e.target.value)} style={{ background: 'rgba(0,0,0,0.3)', color: 'var(--text-primary)' }}>
                  <option value="Oversized Hoodie">Oversized Hoodie</option>
                  <option value="T-Shirt Crewneck">T-Shirt Crewneck</option>
                  <option value="Polo Shirt">Polo Shirt</option>
                  <option value="Sport Jersey">Sport Jersey</option>
                  <option value="Sweatshirt">Sweatshirt</option>
                  <option value="Custom Pants">Custom Pants</option>
                </select>
              </div>

              <div className="form-group" style={{ marginBottom: 0 }}>
                <label className="form-label">Material Component *</label>
                <input 
                  type="text" 
                  className="form-input" 
                  value={material} 
                  onChange={e => setMaterial(e.target.value)} 
                  placeholder="e.g. Terry Cotton" 
                  required 
                />
              </div>

              <div className="form-group" style={{ marginBottom: 0 }}>
                <label className="form-label">Colour Specification *</label>
                <input 
                  type="text" 
                  className="form-input" 
                  value={colour} 
                  onChange={e => setColour(e.target.value)} 
                  placeholder="e.g. Black" 
                  required 
                />
              </div>
            </div>

            {/* Size Breakdown Inputs */}
            <div>
              <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>Size Breakdown Quantities (pcs)</label>
              <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                {['S', 'M', 'L', 'XL', 'XXL'].map(sz => (
                  <div key={sz} style={{ display: 'flex', flexDirection: 'column', gap: '4px', width: '70px' }}>
                    <span style={{ fontSize: '0.75rem', fontWeight: 700, color: 'var(--text-muted)', textAlign: 'center' }}>Size {sz}</span>
                    <input 
                      type="number" 
                      min="0" 
                      placeholder="0"
                      className="form-input"
                      value={sizes[sz]}
                      onChange={e => setSizes({ ...sizes, [sz]: e.target.value })}
                      style={{ textAlign: 'center' }}
                    />
                  </div>
                ))}
              </div>
            </div>

            <button type="submit" className="btn btn-primary" style={{ alignSelf: 'flex-start', padding: '10px 24px' }}>
              Add to Stock Ledger
            </button>
          </form>
        </div>
      )}

    </div>
  );
};

export default MockInventory;
