  const [showChat, setShowChat] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatMessages, setChatMessages] = useState([
    { id: 1, sender: 'Admin', text: 'Hi OM team, please review and approve designs for order #1002.', time: '10:12 AM' },
    { id: 2, sender: 'Order Management', text: 'On it. All designs approved and routed to production.', time: '10:15 AM' }
  ]);

