import React, { useState } from 'react';
import Logo from '../components/Logo';
import { useCRM } from '../context/CRMContext';
import { 
  ShieldCheck, 
  Plus, 
  Package, 
  Truck, 
  Award, 
  Search, 
  Bell, 
  LogOut, 
  ListTodo, 
  ShoppingBag,
  ClipboardList,
  Calendar,
  LayoutDashboard,
  MessageSquare
} from 'lucide-react';
import CustomChart from '../components/CustomChart';

const VendorDashboard = ({ onLogout }) => {
  const { vendors = [], purchaseOrders = [], createPurchaseOrder, currentUser, logoutUser } = useCRM();

  // Navigation: 'dashboard' | 'pos' | 'directory'
  const [activeTab, setActiveTab] = useState('dashboard');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedJobFilter, setSelectedJobFilter] = useState('active'); // 'active' | 'completed'

  // Dropdowns & local feedback
  const [showNotif, setShowNotif] = useState(false);
  const [showProfile, setShowProfile] = useState(false);
  const [localStatuses, setLocalStatuses] = useState({});
  const [success, setSuccess] = useState('');

  // Floating Chat Box State
  const [showChat, setShowChat] = useState(false);
  const [chatInput, setChatInput] = useState('');
  const [chatMessages, setChatMessages] = useState([
    { id: 1, sender: 'Telecaller', text: 'Hi Admin, I just logged 15 warm leads from today\'s batch.', time: '10:12 AM' },
    { id: 2, sender: 'Admin', text: 'Awesome work! Let\'s verify them in the dials tab.', time: '10:15 AM' },
    { id: 3, sender: 'Designer', text: 'Vector outlines zip file is ready and uploaded for Order #1002.', time: '10:30 AM' }
  ]);

  // PO Creator Form local state
  const [vendorName, setVendorName] = useState('');
  const [itemsInput, setItemsInput] = useState('');
  const [costInput, setCostInput] = useState('');

  const handleLogout = () => {
    logoutUser();
    if (onLogout) onLogout();
  };

  const handleCreatePO = (e) => {
    e.preventDefault();
    if (!vendorName || !itemsInput || !costInput) return;

    createPurchaseOrder({
      vendor: vendorName,
      items: itemsInput,
      totalCost: parseFloat(costInput)
    });

    setItemsInput('');
    setCostInput('');
    setSuccess('Purchase Order issued successfully!');
    setTimeout(() => setSuccess(''), 3000);
  };

  const handleMarkReceived = (poId) => {
    setLocalStatuses(prev => ({ ...prev, [poId]: 'Received' }));
    setSuccess(`Job/PO ${poId} marked as Received!`);
    setTimeout(() => setSuccess(''), 3000);
  };

  const getPOStatus = (po) => {
    return localStatuses[po.id] || po.status;
  };

  // Helper: Parse PO items string to detailed attributes
  const parsePOItems = (itemsStr) => {
    const text = itemsStr || '';
    
    // Quantity: e.g. "x100", "x 50", "200 pcs"
    let qty = 100;
    const qtyMatch = text.match(/x\s*(\d+)/i) || text.match(/(\d+)\s*pcs/i) || text.match(/qty:\s*(\d+)/i);
    if (qtyMatch) {
      qty = parseInt(qtyMatch[1]);
    }
    
    // Product category
    let category = 'Blank Apparel';
    if (text.toLowerCase().includes('hoodie') || text.toLowerCase().includes('sweatshirt')) {
      category = 'Hoodie / Terry';
    } else if (text.toLowerCase().includes('tee') || text.toLowerCase().includes('t-shirt') || text.toLowerCase().includes('t shirt')) {
      category = 'T-Shirt';
    } else if (text.toLowerCase().includes('cap') || text.toLowerCase().includes('hat')) {
      category = 'Cap';
    } else if (text.toLowerCase().includes('thread') || text.toLowerCase().includes('needle')) {
      category = 'Supplies / Sewing';
    }
    
    // Color
    let color = 'Mixed';
    const colors = ['black', 'white', 'green', 'red', 'yellow', 'blue', 'orange', 'maroon', 'navy', 'pink'];
    for (const c of colors) {
      if (text.toLowerCase().includes(c)) {
        color = c.charAt(0).toUpperCase() + c.slice(1);
        break;
      }
    }
    
    // Specs: materials or print types
    let specs = 'Premium Cotton';
    if (text.toLowerCase().includes('terry')) {
      specs = 'Terry Fleece';
    } else if (text.toLowerCase().includes('cotton')) {
      specs = 'Cotton - 180g';
      if (text.toLowerCase().includes('affordable')) {
        specs = 'Economy Cotton';
      }
    } else if (text.toLowerCase().includes('polyester') || text.toLowerCase().includes('mesh')) {
      specs = 'Polyester Mesh';
    }
    
    // Sizes
    let size = 'S - XXL';
    if (text.toLowerCase().includes('oversized')) {
      size = 'S - L (Oversized)';
    } else if (text.toLowerCase().includes('size')) {
      const sizeMatch = text.match(/size\s*([a-zA-Z\d\-]+)/i);
      if (sizeMatch) size = sizeMatch[1].toUpperCase();
    }
    
    return { category, specs, qty, size, color };
  };

  // Computations
  // Filter POs matching current user (or show all if admin/no-vendor name matching)
  const myPOs = purchaseOrders.filter(po => {
    if (!currentUser?.name) return true;
    if (currentUser.role === 'admin' || currentUser.role === 'account') return true;
    return po.vendor.toLowerCase().includes(currentUser.name.toLowerCase());
  });

  const activePOsCount = myPOs.filter(po => getPOStatus(po) === 'Sent').length;
  const totalSpend = myPOs.reduce((acc, po) => acc + po.totalCost, 0);

  const vendorRatings = vendors.map(v => ({
    label: v.name.split(' ')[0],
    value: Math.round(v.rating * 20)
  }));

  // Filtering
  const queryLower = searchQuery.toLowerCase();
  
  const filteredJobs = myPOs.filter(po => {
    const matchesSearch = 
      po.id.toLowerCase().includes(queryLower) ||
      po.vendor.toLowerCase().includes(queryLower) ||
      po.items.toLowerCase().includes(queryLower);

    const status = getPOStatus(po);
    if (selectedJobFilter === 'active') {
      return matchesSearch && status === 'Sent';
    } else {
      return matchesSearch && status === 'Received';
    }
  });

  const filteredPOs = myPOs.filter(po => 
    po.id.toLowerCase().includes(queryLower) ||
    po.vendor.toLowerCase().includes(queryLower) ||
    po.items.toLowerCase().includes(queryLower)
  );

  const filteredVendors = vendors.filter(v =>
    v.id.toLowerCase().includes(queryLower) ||
    v.name.toLowerCase().includes(queryLower) ||
    v.category.toLowerCase().includes(queryLower)
  );

  const userInitials = currentUser?.name 
    ? currentUser.name.split(' ').map(n => n[0]).join('').toUpperCase() 
    : 'VE';

  const [isDarkMode, setIsDarkMode] = useState(() => document.body.classList.contains('dark-theme'));

  const handleThemeToggle = () => {
    const newMode = !isDarkMode;
    setIsDarkMode(newMode);
    if (newMode) {
      document.body.classList.add('dark-theme');
    } else {
      document.body.classList.remove('dark-theme');
    }
  };

  const navItems = [
    { id: 'dashboard', label: 'Vendor Jobs Dashboard', icon: <MessageSquare size={18} /> },
    { id: 'pos', label: 'Issue Supply Tickets', icon: <Plus size={18} /> },
    { id: 'directory', label: 'Supplier Ratings & Spend', icon: <Award size={18} /> }
  ];

  return (
    <div className="app-container">
      {/* ── LEFT SIDEBAR ── */}
      <aside className="app-sidebar">
        <div className="sidebar-logo">
          <Logo size={24} color="var(--color-primary)" />
          <span className="sidebar-brand-name">PALLYWEAR</span>
        </div>
        
        <nav className="sidebar-nav">
          {navItems.map((item) => {
            const isActive = activeTab === item.id;
            return (
              <button
                key={item.id}
                onClick={() => { setActiveTab(item.id); setSearchQuery(''); }}
                className={`sidebar-link ${isActive ? 'active' : ''}`}
              >
                {item.icon}
                <span>{item.label}</span>
              </button>
            );
          })}
        </nav>
        
        <div className="sidebar-preferences">
          <div className="preferences-header">Preferences</div>
          <div className="dark-mode-toggle-row">
            <span>Dark Mode</span>
            <label className="switch">
              <input 
                type="checkbox" 
                checked={isDarkMode} 
                onChange={handleThemeToggle} 
              />
              <span className="slider"></span>
            </label>
          </div>
        </div>
      </aside>

      {/* ── RIGHT MAIN CONTENT ── */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        {/* Header inside right content pane */}
        <header style={{ 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center', 
          padding: '20px 24px', 
          borderBottom: '1px solid var(--border-color)',
          background: 'var(--bg-card)',
          flexShrink: 0
        }}>
          <div>
            <h1 style={{ fontSize: '1.25rem', fontWeight: 800, color: 'var(--text-primary)', margin: 0, textTransform: 'capitalize' }}>
              {activeTab === 'dashboard' ? 'Vendor Jobs Dashboard' : activeTab === 'pos' ? 'Supply Tickets' : 'Supplier Ratings & Spend'}
            </h1>
            <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)', marginTop: '2px' }}>
              Pallywear Vendor / <span style={{ color: 'var(--text-primary)', fontWeight: 600 }}>{activeTab === 'dashboard' ? 'Vendor Jobs Dashboard' : activeTab === 'pos' ? 'Supply Tickets' : 'Supplier Ratings & Spend'}</span>
            </div>
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
            {/* Search Input */}
            <div style={{ position: 'relative' }}>
              <Search size={14} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
              <input
                type="text"
                placeholder="Search..."
                value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                style={{ 
                  paddingLeft: '32px', 
                  paddingRight: '12px', 
                  height: '36px', 
                  fontSize: '0.82rem', 
                  background: 'var(--bg-app)', 
                  border: '1px solid var(--border-color)', 
                  borderRadius: '18px', 
                  color: 'var(--text-primary)', 
                  width: '200px',
                  transition: 'var(--transition-smooth)'
                }}
              />
            </div>

            {/* Notification Bell */}
            <div style={{ position: 'relative' }}>
              <button 
                onClick={() => { setShowNotif(!showNotif); setShowProfile(false); }} 
                className="btn btn-outline" 
                style={{ width: '36px', height: '36px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 0 }}
              >
                <Bell size={16} />
              </button>
              {showNotif && (
                <div className="glass-panel animate-fade-in" style={{ position: 'absolute', right: 0, top: '44px', width: '280px', padding: '16px', zIndex: 1000 }}>
                  <div style={{ fontWeight: 700, fontSize: '0.88rem', marginBottom: '8px' }}>Notifications</div>
                  <div style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>System status normal. Active role: vendor</div>
                </div>
              )}
            </div>

            {/* Profile Dropdown */}
            <div style={{ position: 'relative' }}>
              <button 
                onClick={() => { setShowProfile(!showProfile); setShowNotif(false); }}
                style={{ 
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                  padding: '4px 12px 4px 6px',
                  borderRadius: '20px',
                  background: 'var(--bg-app)',
                  border: '1px solid var(--border-color)',
                  color: 'var(--text-primary)',
                  cursor: 'pointer'
                }}
              >
                <img 
                  src={currentUser?.name ? `https://ui-avatars.com/api/?name=${encodeURIComponent(currentUser.name)}&background=3b82f6&color=fff&bold=true` : "https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?auto=format&fit=facearea&facepad=2&w=256&h=256&q=80"}
                  alt={currentUser?.name || "User"}
                  style={{ width: '28px', height: '28px', borderRadius: '50%', objectFit: 'cover', border: '1px solid var(--border-color)' }}
                />
                <span style={{ fontSize: '0.82rem', fontWeight: 600 }}>{currentUser?.name || 'Partner'}</span>
              </button>
              
              {showProfile && (
                <div className="glass-panel animate-fade-in" style={{ position: 'absolute', right: 0, top: '44px', width: '220px', padding: '16px', zIndex: 1000, display: 'flex', flexDirection: 'column', gap: '8px' }}>
                  <div style={{ fontSize: '0.85rem', fontWeight: 800, color: 'var(--text-primary)' }}>{currentUser?.name || 'User Profile'}</div>
                  <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{currentUser?.email || 'vendor@pallywear.com'}</div>
                  <hr style={{ border: 'none', borderBottom: '1px solid var(--border-color)', margin: '8px 0' }} />
                  <button onClick={handleLogout} className="btn btn-danger" style={{ width: '100%', padding: '8px', fontSize: '0.78rem', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '6px' }}>
                    <LogOut size={12} /> Sign Out (Logout)
                  </button>
                </div>
              )}
            </div>
          </div>
        </header>

        {/* Scrollable View Area */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '24px' }}>
          
          {/* Welcome row */}
          <div style={{ marginBottom: '24px' }}>
            <h2 style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--text-primary)', margin: 0, letterSpacing: '-0.02em' }}>Vendor Portal</h2>
            <div style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginTop: '4px' }}>
              Welcome back, <span style={{ fontWeight: 700, color: 'var(--color-primary)' }}>{currentUser?.name || 'navin'}</span>. Manage assigned jobs and track production status.
            </div>
          </div>

          {success && (
            <div style={{ padding: '12px 18px', background: 'rgba(16, 185, 129, 0.15)', border: '1px solid rgba(16, 185, 129, 0.25)', borderRadius: '10px', color: '#10b981', fontSize: '0.88rem', fontWeight: 600, marginBottom: '24px' }}>
              {success}
            </div>
          )}

          {/* TAB 1: ASSIGNED JOBS Snapshots */}
          {activeTab === 'dashboard' && (
            <div className="animate-fade-in" style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
              {/* Highlight Cards Row */}
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
                
                {/* Active Jobs Card */}
                <div 
                  onClick={() => setSelectedJobFilter('active')}
                  className="glass-panel"
                  style={{
                    padding: '24px',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '16px',
                    cursor: 'pointer',
                    border: selectedJobFilter === 'active' ? '2px solid var(--color-primary)' : '1px solid var(--border-color)',
                    background: selectedJobFilter === 'active' ? 'var(--color-primary-light)' : 'var(--bg-card)',
                    transform: selectedJobFilter === 'active' ? 'translateY(-2px)' : 'none',
                    transition: 'var(--transition-smooth)'
                  }}
                >
                  <div style={{ 
                    width: '46px', height: '46px', borderRadius: '50%', 
                    backgroundColor: 'rgba(91, 78, 232, 0.15)', color: 'var(--color-primary)', 
                    display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0
                  }}>
                    <ClipboardList size={20} />
                  </div>
                  <div style={{ display: 'flex', flexDirection: 'column' }}>
                    <span style={{ fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '0.04em' }}>Active Assigned Jobs</span>
                    <h3 style={{ fontSize: '1.45rem', fontWeight: 800, color: 'var(--text-primary)', margin: 0 }}>{activePOsCount}</h3>
                    <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Orders pending supply</span>
                  </div>
                </div>

                {/* Completed / Received Card */}
                <div 
                  onClick={() => setSelectedJobFilter('completed')}
                  className="glass-panel"
                  style={{
                    padding: '24px',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '16px',
                    cursor: 'pointer',
                    border: selectedJobFilter === 'completed' ? '2px solid #10b981' : '1px solid var(--border-color)',
                    background: selectedJobFilter === 'completed' ? 'rgba(16, 185, 129, 0.08)' : 'var(--bg-card)',
                    transform: selectedJobFilter === 'completed' ? 'translateY(-2px)' : 'none',
                    transition: 'var(--transition-smooth)'
                  }}
                >
                  <div style={{ 
                    width: '46px', height: '46px', borderRadius: '50%', 
                    backgroundColor: 'rgba(16, 185, 129, 0.15)', color: '#10b981', 
                    display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0
                  }}>
                    <ShoppingBag size={20} />
                  </div>
                  <div style={{ display: 'flex', flexDirection: 'column' }}>
                    <span style={{ fontSize: '0.78rem', fontWeight: 600, color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '0.04em' }}>Completed Jobs</span>
                    <h3 style={{ fontSize: '1.45rem', fontWeight: 800, color: 'var(--text-primary)', margin: 0 }}>{myPOs.length - activePOsCount}</h3>
                    <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Delivered successfully</span>
                  </div>
                </div>

              </div>

              {/* VENDOR JOBS / ASSIGNED ORDERS Table container */}
              <div className="glass-panel" style={{ padding: '24px' }}>
                
                {/* Table Header Row */}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', flexWrap: 'wrap', gap: '12px' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                    <div style={{ width: '36px', height: '36px', borderRadius: '8px', backgroundColor: 'rgba(91, 78, 232, 0.12)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--color-primary)' }}>
                      <ClipboardList size={18} />
                    </div>
                    <div>
                      <h3 style={{ fontSize: '1.05rem', fontWeight: 800, color: 'var(--text-primary)', margin: 0 }}>
                        VENDOR JOBS / ASSIGNED ORDERS ({filteredJobs.length})
                      </h3>
                    </div>
                  </div>

                  <div style={{ position: 'relative' }}>
                    <Search size={14} style={{ position: 'absolute', top: '50%', left: '12px', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
                    <input 
                      type="text" 
                      placeholder="Search jobs..." 
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      style={{ 
                        width: '240px', 
                        height: '34px', 
                        borderRadius: '17px', 
                        paddingLeft: '34px', 
                        fontSize: '0.8rem', 
                        border: '1px solid var(--border-color)',
                        background: 'var(--bg-app)',
                        outline: 'none',
                        color: 'var(--text-primary)',
                        transition: 'var(--transition-smooth)'
                      }}
                    />
                  </div>
                </div>

                {/* Table */}
                <div className="table-container">
                  <table className="custom-table">
                    <thead>
                      <tr>
                        <th>Job ID</th>
                        <th>Product / Category</th>
                        <th>Specs</th>
                        <th>Quantity</th>
                        <th>Size</th>
                        <th>Color</th>
                        <th style={{ textAlign: 'right' }}>Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredJobs.map((po) => {
                        const parsed = parsePOItems(po.items);
                        const status = getPOStatus(po);

                        return (
                          <tr key={po.id}>
                            <td style={{ fontWeight: 800, color: 'var(--text-primary)' }}>{po.id}</td>
                            <td>
                              <div style={{ fontWeight: 700, color: 'var(--text-primary)' }}>{parsed.category}</div>
                              <div style={{ fontSize: '0.72rem', color: 'var(--text-secondary)' }}>Supplier: {po.vendor}</div>
                            </td>
                            <td style={{ color: 'var(--text-secondary)', fontSize: '0.85rem' }}>{parsed.specs}</td>
                            <td style={{ fontWeight: 700, color: 'var(--text-primary)' }}>{parsed.qty} pcs</td>
                            <td style={{ fontWeight: 600, color: 'var(--text-primary)' }}>{parsed.size}</td>
                            <td>
                              <span style={{ 
                                display: 'inline-flex', alignItems: 'center', gap: '6px', fontSize: '0.82rem', fontWeight: 600, color: 'var(--text-primary)'
                              }}>
                                <span style={{ 
                                  width: '10px', height: '10px', borderRadius: '50%', 
                                  backgroundColor: parsed.color.toLowerCase() === 'white' ? '#f3f4f6' : parsed.color.toLowerCase(),
                                  border: '1px solid var(--border-color)'
                                }} />
                                {parsed.color}
                              </span>
                            </td>
                            <td style={{ textAlign: 'right' }}>
                              {status === 'Sent' ? (
                                <button 
                                  onClick={() => handleMarkReceived(po.id)}
                                  className="btn btn-success"
                                  style={{ padding: '6px 12px', fontSize: '0.75rem' }}
                                >
                                  Mark Received
                                </button>
                              ) : (
                                <span className="badge badge-success">Received</span>
                              )}
                            </td>
                          </tr>
                        );
                      })}
                      {filteredJobs.length === 0 && (
                        <tr>
                          <td colSpan="7" style={{ textAlign: 'center', color: 'var(--text-muted)', padding: '40px', fontStyle: 'italic' }}>
                            No assigned vendor jobs found.
                          </td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>

              </div>
            </div>
          )}

          {/* TAB 2: ISSUE PURCHASE ORDERS */}
          {activeTab === 'pos' && (
            <div className="animate-fade-in" style={{ display: 'grid', gridTemplateColumns: '1fr 2fr', gap: '24px' }}>
              
              {/* Creator Form */}
              <div className="glass-panel" style={{ padding: '24px', height: 'fit-content' }}>
                <h3 style={{ fontSize: '1.05rem', fontWeight: 800, color: 'var(--text-primary)', marginBottom: '20px', display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <Plus size={18} style={{ color: 'var(--color-primary)' }} />
                  Issue Supply PO
                </h3>

                <form onSubmit={handleCreatePO} style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                  <div className="form-group" style={{ marginBottom: 0 }}>
                    <label className="form-label" style={{ fontWeight: 600 }}>Select Supply Vendor</label>
                    <select 
                      className="form-input" 
                      value={vendorName} 
                      onChange={e => setVendorName(e.target.value)}
                      style={{ background: 'var(--bg-card)', color: 'var(--text-primary)', border: '1px solid var(--border-color)', borderRadius: '10px' }}
                      required
                    >
                      <option value="">-- Choose Vendor --</option>
                      {vendors.map(v => (
                        <option key={v.id} value={v.name}>{v.name} ({v.category})</option>
                      ))}
                    </select>
                  </div>

                  <div className="form-group" style={{ marginBottom: 0 }}>
                    <label className="form-label" style={{ fontWeight: 600 }}>Procured Blank Items / Description</label>
                    <input 
                      type="text" 
                      className="form-input" 
                      value={itemsInput} 
                      onChange={e => setItemsInput(e.target.value)} 
                      placeholder="e.g. Blank Cotton Tee Black size L x150" 
                      style={{ border: '1px solid var(--border-color)', borderRadius: '10px', background: 'var(--bg-card)', color: 'var(--text-primary)' }}
                      required 
                    />
                  </div>

                  <div className="form-group" style={{ marginBottom: 0 }}>
                    <label className="form-label" style={{ fontWeight: 600 }}>Total Cost ($)</label>
                    <input 
                      type="number" 
                      className="form-input" 
                      value={costInput} 
                      onChange={e => setCostInput(e.target.value)} 
                      placeholder="e.g. 850" 
                      style={{ border: '1px solid var(--border-color)', borderRadius: '10px', background: 'var(--bg-card)', color: 'var(--text-primary)' }}
                      required 
                    />
                  </div>

                  <button 
                    type="submit" 
                    className="btn btn-primary"
                    style={{ 
                      background: 'linear-gradient(135deg, var(--color-primary) 0%, var(--color-primary-hover) 100%)', 
                      color: '#ffffff', 
                      border: 'none', 
                      height: '42px', 
                      borderRadius: '10px', 
                      fontWeight: 700, 
                      cursor: 'pointer', 
                      marginTop: '10px',
                      boxShadow: '0 4px 10px rgba(91, 78, 232, 0.2)' 
                    }}
                  >
                    Issue Supply Ticket
                  </button>
                </form>
              </div>

              {/* Purchase Orders List */}
              <div className="glass-panel" style={{ padding: '24px' }}>
                <h3 style={{ fontSize: '1.05rem', fontWeight: 800, color: 'var(--text-primary)', marginBottom: '20px' }}>Issued Purchase Orders (POs)</h3>
                <div className="table-container">
                  <table className="custom-table">
                    <thead>
                      <tr>
                        <th>PO ID</th>
                        <th>Supplier / Vendor</th>
                        <th>Materials / Items</th>
                        <th>Total Cost</th>
                        <th>Status</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredPOs.map(po => {
                        const status = getPOStatus(po);
                        return (
                          <tr key={po.id}>
                            <td style={{ fontWeight: 800, color: 'var(--text-primary)' }}>{po.id}</td>
                            <td style={{ fontWeight: 700, color: 'var(--text-primary)' }}>{po.vendor}</td>
                            <td style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>{po.items}</td>
                            <td style={{ fontWeight: 700, color: 'var(--text-primary)' }}>${po.totalCost}</td>
                            <td>
                              <span className={`badge ${status === 'Received' ? 'badge-success' : 'badge-warning'}`}>
                                {status}
                              </span>
                            </td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
              </div>

            </div>
          )}

          {/* TAB 3: RATINGS & DIRECTORY */}
          {activeTab === 'directory' && (
            <div className="animate-fade-in" style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
              <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '24px' }}>
                
                {/* Vendor Directory */}
                <div className="glass-panel" style={{ padding: '24px' }}>
                  <h3 style={{ fontSize: '1.05rem', fontWeight: 800, color: 'var(--text-primary)', marginBottom: '20px' }}>Authorized Supply Vendors</h3>
                  <div className="table-container">
                    <table className="custom-table">
                      <thead>
                        <tr>
                          <th>Vendor ID</th>
                          <th>Name</th>
                          <th>Category</th>
                          <th>Base Pricing</th>
                          <th>Rating</th>
                        </tr>
                      </thead>
                      <tbody>
                        {filteredVendors.map(v => (
                          <tr key={v.id}>
                            <td style={{ fontWeight: 800, color: 'var(--text-primary)' }}>{v.id}</td>
                            <td style={{ fontWeight: 700, color: 'var(--text-primary)' }}>{v.name}</td>
                            <td style={{ color: 'var(--text-secondary)' }}>{v.category}</td>
                            <td style={{ fontFamily: 'monospace', fontWeight: 600, color: 'var(--text-primary)' }}>{v.materialPrice}</td>
                            <td>
                              <span className="badge badge-purple" style={{ display: 'inline-flex', alignItems: 'center', gap: '4px' }}>
                                <ShieldCheck size={12} />
                                {v.rating} / 5.0
                              </span>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>

                {/* Ratings Chart */}
                <div className="glass-panel" style={{ padding: '24px' }}>
                  <h3 style={{ fontSize: '1.05rem', fontWeight: 800, color: 'var(--text-primary)', marginBottom: '20px' }}>Supplier Quality Rating (%)</h3>
                  <CustomChart type="bar" data={vendorRatings} color="vendor" height={200} />
                </div>

              </div>
            </div>
          )}

        </div>

      </div>

      {/* Floating Chat Icon (matching bottom right of mockup) */}
      <div 
        onClick={() => setShowChat(!showChat)}
        style={{ position: 'fixed', bottom: '24px', right: '24px', width: '48px', height: '48px', borderRadius: '50%', background: '#0f172a', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 12px rgba(0,0,0,0.15)', cursor: 'pointer', zIndex: 9999 }}
      >
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#ffffff" strokeWidth="2">
          <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
        </svg>
      </div>

      {/* Floating Interactive Chat Drawer */}
      {showChat && (
        <div style={{
          position: 'fixed',
          bottom: '84px',
          right: '24px',
          width: '320px',
          height: '400px',
          background: '#ffffff',
          border: '1px solid #cbd5e1',
          borderRadius: '16px',
          boxShadow: '0 10px 25px -5px rgba(0, 0, 0, 0.1)',
          display: 'flex',
          flexDirection: 'column',
          zIndex: 99999
        }}>
          {/* Header */}
          <div style={{ padding: '12px 16px', background: '#0f172a', borderTopLeftRadius: '16px', borderTopRightRadius: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', color: '#ffffff' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
              <span style={{ width: '8px', height: '8px', borderRadius: '50%', background: '#10b981', display: 'inline-block' }}></span>
              <span style={{ fontSize: '0.85rem', fontWeight: 800 }}>CRM Staff Chat</span>
            </div>
            <button onClick={() => setShowChat(false)} style={{ background: 'transparent', border: 'none', color: '#ffffff', cursor: 'pointer', fontSize: '0.85rem' }}>✕</button>
          </div>

          {/* Messages Body */}
          <div style={{ flex: 1, padding: '12px', overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: '8px', background: '#f8fafc' }}>
            {chatMessages.map(msg => (
              <div key={msg.id} style={{ alignSelf: msg.sender === currentUser?.role ? 'flex-end' : 'flex-start', maxWidth: '80%' }}>
                <div style={{ fontSize: '0.7rem', color: '#64748b', marginBottom: '2px', textAlign: msg.sender === currentUser?.role ? 'right' : 'left' }}>
                  {msg.sender} · {msg.time}
                </div>
                <div style={{
                  padding: '8px 12px',
                  borderRadius: '12px',
                  background: msg.sender === currentUser?.role ? '#3b82f6' : '#ffffff',
                  color: msg.sender === currentUser?.role ? '#ffffff' : '#0f172a',
                  border: msg.sender === currentUser?.role ? 'none' : '1px solid #cbd5e1',
                  fontSize: '0.8rem',
                  lineHeight: '1.4'
                }}>
                  {msg.text}
                </div>
              </div>
            ))}
          </div>

          {/* Footer Input */}
          <form 
            onSubmit={(e) => {
              e.preventDefault();
              if (!chatInput.trim()) return;
              const newMsg = {
                id: Date.now(),
                sender: currentUser?.role || 'user',
                text: chatInput.trim(),
                time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
              };
              setChatMessages([...chatMessages, newMsg]);
              setChatInput('');
            }}
            style={{ padding: '8px 12px', borderTop: '1px solid #cbd5e1', display: 'flex', gap: '8px', background: '#ffffff', borderBottomLeftRadius: '16px', borderBottomRightRadius: '16px' }}
          >
            <input
              type="text"
              placeholder="Type a message..."
              value={chatInput}
              onChange={(e) => setChatInput(e.target.value)}
              style={{ flex: 1, border: '1px solid #cbd5e1', borderRadius: '20px', padding: '6px 12px', fontSize: '0.8rem', outline: 'none', color: '#0f172a' }}
            />
            <button type="submit" style={{ background: '#3b82f6', color: '#ffffff', border: 'none', borderRadius: '50%', width: '28px', height: '28px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', fontSize: '0.78rem', fontWeight: 800 }}>
              ➔
            </button>
          </form>
        </div>
      )}

    </div>
  );
};

export default VendorDashboard;
