import React from 'react';

const StatCard = ({ title, value, subtext, icon: Icon, color, trend, progressRing, onClick }) => {
  const accentColor = `var(--color-${color || 'admin'})`;
  
  // Dynamic icon background helper
  const bgGlow = `rgba(${color === 'marketing' ? '6, 182, 212' : 
                        color === 'account' ? '16, 185, 129' :
                        color === 'design' ? '217, 70, 239' :
                        color === 'digitizer' ? '139, 92, 246' :
                        color === 'order' ? '249, 115, 22' :
                        color === 'production' ? '59, 130, 246' :
                        color === 'delivery' ? '244, 63, 94' :
                        color === 'telecaller' ? '236, 72, 153' :
                        color === 'vendor' ? '20, 184, 166' :
                        '234, 179, 8'}, 0.12)`;

  // Circular progress math
  const radius = 18;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = progressRing 
    ? circumference - (progressRing.percentage / 100) * circumference 
    : 0;

  return (
    <div 
      className="glass-panel animate-fade-in" 
      onClick={onClick}
      style={{ 
        padding: '20px', 
        display: 'flex',
        alignItems: 'center',
        gap: '16px',
        background: 'var(--bg-card)',
        borderRadius: '16px',
        border: '1px solid var(--border-color)',
        minWidth: '220px',
        cursor: onClick ? 'pointer' : 'default'
      }}
    >
      {/* Icon circular wrapper */}
      <div style={{
        width: '46px',
        height: '46px',
        borderRadius: '50%',
        background: bgGlow,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        color: accentColor,
        flexShrink: 0
      }}>
        {Icon && <Icon size={20} />}
      </div>

      {/* Metric details */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: '2px' }}>
        <span style={{ 
          fontSize: '0.78rem', 
          fontWeight: 600, 
          color: 'var(--text-secondary)',
          textTransform: 'uppercase',
          letterSpacing: '0.04em'
        }}>
          {title}
        </span>
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
          <h3 style={{ 
            fontSize: '1.45rem', 
            fontWeight: 800, 
            color: 'var(--text-primary)', 
            letterSpacing: '-0.02em', 
            margin: 0 
          }}>
            {value}
          </h3>

          {trend && (
            <span style={{ 
              fontSize: '0.72rem', 
              fontWeight: 700, 
              color: trend.isPositive ? '#10b981' : '#f43f5e',
              background: trend.isPositive ? 'rgba(16, 185, 129, 0.1)' : 'rgba(244, 63, 94, 0.1)',
              padding: '2px 6px',
              borderRadius: '6px',
              display: 'inline-block'
            }}>
              {trend.isPositive ? '+' : ''}{trend.percentage}%
            </span>
          )}
        </div>

        {subtext && (
          <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: '2px' }}>
            {subtext}
          </span>
        )}
      </div>

      {progressRing && (
        <div style={{ position: 'relative', width: '40px', height: '40px', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
          <svg width="40" height="40" style={{ transform: 'rotate(-90deg)' }}>
            <circle 
              cx="20" cy="20" r={radius} 
              fill="transparent" 
              stroke="rgba(0,0,0,0.04)" 
              strokeWidth="3" 
            />
            <circle 
              cx="20" cy="20" r={radius} 
              fill="transparent" 
              stroke={accentColor} 
              strokeWidth="3" 
              strokeDasharray={circumference}
              strokeDashoffset={strokeDashoffset}
              strokeLinecap="round"
              style={{ transition: 'stroke-dashoffset 0.8s ease-in-out' }}
            />
          </svg>
          <span style={{ position: 'absolute', fontSize: '0.68rem', fontWeight: 700, color: 'var(--text-primary)' }}>
            {progressRing.percentage}%
          </span>
        </div>
      )}
    </div>
  );
};

export default StatCard;
